mapper.select:
SELECT DTL_C 	AS CD,
	   DTL_C_NM AS CD_NM,
	   GRP_C 	AS GRP_CD 
  FROM KRBA_DTL_C  
 WHERE USYN=1

   AND GRP_C = #{GRP_C , jdbcType=VARCHAR}


   AND HGRK_GRP_C = #{HGRK_GRP_C , jdbcType=VARCHAR}


   AND HGRK_DTL_C = #{HGRK_DTL_C , jdbcType=VARCHAR}


   AND HGRK_GRP_C = #{HRNK_RBA_RSK_C , jdbcType=VARCHAR}
   AND HGRK_DTL_C = #{HRNK_RBA_RSK_C_V , jdbcType=VARCHAR}

ORDER BY SNO

SELECT RSK_FAC AS CD, RSK_FAC_NM AS CD_NM, RSK_CATG AS GRP_CD FROM KRBA_RSK_FAC_I WHERE 1=1
AND RSK_CATG = #{HGRK_DTL_C , jdbcType=VARCHAR}
ORDER BY RSK_FAC

SELECT B.RSK_FAC||A.RSK_EVT AS CD, CASE WHEN B.RSK_CATG IN ('2', '4') THEN A.RSK_EVT_NM||' ('||B.RSK_FAC_NM||')' ELSE A.RSK_EVT_NM END AS CD_NM FROM KRBA_RSK_EVT_I A , KRBA_RSK_FAC_I B WHERE 1=1 AND A.RSK_CATG = B.RSK_CATG AND A.RSK_FAC = B.RSK_FAC
AND A.RSK_CATG = #{HGRK_DTL_C , jdbcType=VARCHAR}
AND A.RSK_FAC = #{HRNK_RBA_RSK_C , jdbcType=VARCHAR}
AND A.RSK_CATG = #{HRNK_RBA_RSK_C_V , jdbcType=VARCHAR}
ORDER BY A.RSK_CATG, A.RSK_FAC, A.RSK_EVT

SELECT *
  FROM NIC41B
 WHERE DPRT_CD = #{SEARCH_VALUE,jdbcType=VARCHAR}

SELECT DPRT_CD, DPRT_NM, HG_RNK_DPRT_CD, MOFC_BRN_CCD, DPRT_POST_NO, TEL_NO, USE_CCD, AML_CRT_DT, KFB_DPRT_CD FROM 
    (SELECT DPRT_CD, DPRT_NM, HG_RNK_DPRT_CD, MOFC_BRN_CCD, DPRT_POST_NO, TEL_NO, USE_CCD, AML_CRT_DT, KFB_DPRT_CD FROM NIC41B
      UNION ALL 
     SELECT '9999' ,'영업점' , '999', 'M','','','','','' FROM DUAL
     )
 WHERE DPRT_CD = #{SEARCH_VALUE,jdbcType=VARCHAR}

SELECT A.DPRT_CD, A.DPRT_NM, A.HG_RNK_DPRT_CD, A.MOFC_BRN_CCD, A.DPRT_POST_NO, A.TEL_NO, A.USE_CCD, A.AML_CRT_DT, A.KFB_DPRT_CD
  FROM NIC41B A
       JOIN KRBA_EXPS_SCOR_I B
         ON A.DPRT_CD = B.BRNO
 WHERE 1=1
   AND B.BAS_YYYY = #{BAS_YYYY,jdbcType=VARCHAR}
   AND B.VALT_TRN = #{VALT_TRN,jdbcType=NUMERIC}
   AND A.DPRT_CD  = #{SEARCH_VALUE,jdbcType=VARCHAR}

SELECT COUNT(*) AS CNT /*업무프로세스결재권*/ FROM ( SELECT AAAA.* ,(SELECT ROLE_NM FROM C_ROLE WHERE ROLE_ID = AAAA.GYLJ_STEP_ID) AS GYLJ_STEP FROM ( SELECT AAA.*, (SELECT GYLJ_ROLE_ID FROM SRBA_GYLJ_D WHERE GYLJ_LINE_G_C=AAA.GYLJ_G_C AND SNO='1') AS FIRST_ROLE_ID, CASE WHEN (GYLJ_S_C_NM = '저장' OR GYLJ_S_C_NM = '미수행') AND DPRT_CD ='J5' /*준법 부서 커스터마이징 필요*/ THEN (SELECT GYLJ_ROLE_ID||'' FROM SRBA_GYLJ_D WHERE GYLJ_LINE_G_C='W01' AND SNO='1') WHEN (GYLJ_S_C_NM = '저장' OR GYLJ_S_C_NM = '미수행') AND DPRT_CD !='J5' /*준법 부서 커스터마이징 필요*/ THEN (SELECT GYLJ_ROLE_ID||'' FROM SRBA_GYLJ_D WHERE GYLJ_LINE_G_C='W01' AND SNO='1') ELSE GYLJ_ROLE_ID||'' END AS GYLJ_STEP_ID FROM ( SELECT BB.DPRT_CD ,BB.DPRT_NM ,AA.AML_TJ_BRNO_YN ,DECODE(AA.AML_TJ_BRNO_YN,'1','Y','N') AS TJ_BRNO_YN ,NVL(CC.CNT,0) CNT ,AA.BAS_YYMM ,DD.GYLJ_ID /*,DECODE(AA.AML_TJ_BRNO_YN,'0','11',DD.GYLJ_S_C) AS GYLJ_S_C ,(SELECT DECODE(AA.AML_TJ_BRNO_YN,'0','완료',DTL_C_NM) AS NAME FROM SRBA_DTL_C WHERE USYN=1 AND GRP_C='R325' AND DTL_C= DECODE(DD.GYLJ_S_C,NULL,0,DD.GYLJ_S_C) ) AS GYLJ_S_C_NM*/ ,DECODE(BB.MOFC_BRN_CCD,'B','11',DD.GYLJ_S_C) AS GYLJ_S_C ,(SELECT DECODE(BB.MOFC_BRN_CCD,'B','완료',DTL_C_NM) AS NAME FROM SRBA_DTL_C WHERE USYN=1 AND GRP_C='R325' AND DTL_C= DECODE(DD.GYLJ_S_C,NULL,0,DD.GYLJ_S_C) ) AS GYLJ_S_C_NM ,DD.GYLJ_JKW_NO ,(SELECT MAX(GYLJ_G_C) FROM SRBA_GYLJ_H WHERE GYLJ_ID=DD.GYLJ_ID) AS GYLJ_G_C ,GET_LOGINID_NAME(GYLJ_JKW_NO) AS GYLJ_JKW_NM ,DD.GYLJ_ROLE_ID ,(SELECT ROLE_NM FROM C_ROLE WHERE ROLE_ID = DD.GYLJ_ROLE_ID) AS ROLE_NM ,BB.HG_RNK_DPRT_CD FROM SRBA_VALT_BRNO AA , NIC41B BB, ( SELECT A.BAS_YYMM,B.VALT_BRNO,COUNT(*) AS CNT FROM SRBA_V_PROC_M A,SRBA_V_PROC_BRNO B WHERE A.BAS_YYMM=B.BAS_YYMM(+) AND A.PROC_FLD_C=B.PROC_FLD_C(+) AND A.PROC_LGDV_C=B.PROC_LGDV_C(+) AND A.PROC_MDDV_C=B.PROC_MDDV_C(+) AND A.PROC_SMDV_C=B.PROC_SMDV_C(+) AND A.USYN='1' AND A.PROC_FLD_C='1' AND B.TGT_YN ='1' AND B.BAS_YYMM = (SELECT MAX(BAS_YYMM) AS MAX_BAY_YYMM FROM SRBA_VALT_SCHD_M WHERE BAS_YYMM != '999912') GROUP BY A.BAS_YYMM,B.VALT_BRNO ) CC , (SELECT D.BAS_YYMM,D.VALT_BRNO,D.GYLJ_S_C,GYLJ_ID,GYLJ_JKW_NO,GYLJ_ROLE_ID FROM ( SELECT BAS_YYMM,VALT_BRNO,GYLJ_S_C,GYLJ_ID,GYLJ_JKW_NO,GYLJ_ROLE_ID ,ROW_NUMBER() OVER (PARTITION BY VALT_BRNO ORDER BY GYLJ_ID DESC) RNUM FROM SRBA_V_PROC_GYLJ WHERE BAS_YYMM =(SELECT MAX(BAS_YYMM) AS MAX_BAY_YYMM FROM SRBA_VALT_SCHD_M WHERE BAS_YYMM != '999912') ) D WHERE RNUM =1 ) DD WHERE USE_CCD='Y' AND AA.BRNO=BB.DPRT_CD AND AA.BRNO=CC.VALT_BRNO(+) AND AA.BRNO=DD.VALT_BRNO(+) AND AA.BAS_YYMM = (SELECT MAX(BAS_YYMM) AS MAX_BAY_YYMM FROM SRBA_VALT_SCHD_M WHERE BAS_YYMM != '999912') ) AAA )AAAA WHERE GYLJ_STEP_ID = #{ROLE_ID}
AND DPRT_CD = #{VALT_BRNO, jdbcType=VARCHAR} -- 부점
AND DPRT_CD = #{VALT_BRNO, jdbcType=VARCHAR} -- 부점
)

SELECT COUNT(1) AS CNT FROM ( SELECT BAS_YYMM ,VALT_BRNO ,(SELECT DPRT_NM FROM NIC41B WHERE DPRT_CD = VALT_BRNO) VALT_BRNM ,VALT01 ,VALT02 ,GYLJ_S_C /* 결재상태코드 */ ,NVL( (SELECT DTL_C_NM FROM SRBA_DTL_C WHERE GRP_C = 'R325' AND DTL_C = GYLJ_S_C) ,'미진행') AS GYLJ_S_C_NM /* 결재상태 */ ,GYLJ_ROLE_ID ,GYLJ_ID FROM( SELECT T01.BAS_YYMM AS BAS_YYMM ,T02.VALT_BRNO AS VALT_BRNO ,COUNT(T01.BAS_YYMM) AS VALT01 ,(SELECT COUNT(*) FROM SRBA_V_HRSK_R WHERE BAS_YYMM = T01.BAS_YYMM AND VALT_BRNO = T02.VALT_BRNO) AS VALT02 ,(SELECT DISTINCT GYLJ_S_C FROM SRBA_V_HRSK_R WHERE BAS_YYMM = T01.BAS_YYMM AND VALT_BRNO = T02.VALT_BRNO) AS GYLJ_S_C ,(SELECT DISTINCT GYLJ_ID FROM SRBA_V_HRSK_R WHERE BAS_YYMM = T01.BAS_YYMM AND VALT_BRNO = T02.VALT_BRNO) AS GYLJ_ID ,(SELECT DISTINCT GYLJ_ROLE_ID FROM SRBA_V_HRSK_R WHERE BAS_YYMM = T01.BAS_YYMM AND VALT_BRNO = T02.VALT_BRNO) AS GYLJ_ROLE_ID FROM SRBA_V_PROC_M T01 , SRBA_V_PROC_BRNO T02 , SRBA_VALT_BRNO T03 WHERE T01.BAS_YYMM = T02.BAS_YYMM AND T01.PROC_FLD_C = T02.PROC_FLD_C AND T01.PROC_FLD_C = T02.PROC_FLD_C AND T01.PROC_LGDV_C = T02.PROC_LGDV_C AND T01.PROC_MDDV_C = T02.PROC_MDDV_C AND T01.PROC_SMDV_C = T02.PROC_SMDV_C AND T01.BAS_YYMM = T03.BAS_YYMM AND T02.VALT_BRNO = T03.BRNO AND T02.BAS_YYMM = T03.BAS_YYMM AND T01.BAS_YYMM = (SELECT MAX(BAS_YYMM) AS MAX_BAY_YYMM FROM SRBA_VALT_SCHD_M WHERE BAS_YYMM != '999912') AND T01.VALT_METH_C = '2' AND T02.TGT_YN = '1' GROUP BY T01.BAS_YYMM,T02.VALT_BRNO ORDER BY T02.VALT_BRNO ) )AA WHERE 1=1 AND AA.VALT01 = AA.VALT02
AND AA.VALT_BRNO = #{VALT_BRNO, jdbcType=VARCHAR} AND (AA.GYLJ_S_C IS NULL OR AA.GYLJ_S_C IN ('0','11','22'))
AND (AA.GYLJ_ROLE_ID = #{ROLE_ID, jdbcType=VARCHAR} OR ( AA.GYLJ_S_C IN ('0','11') AND AA.VALT_BRNO = #{VALT_BRNO, jdbcType=VARCHAR}))
AND AA.GYLJ_ID <> 0 AND AA.GYLJ_ROLE_ID = #{ROLE_ID, jdbcType=VARCHAR}
AND AA.VALT_BRNO = #{VALT_BRNO, jdbcType=VARCHAR} AND AA.GYLJ_ID <> 0 AND AA.GYLJ_ROLE_ID = #{ROLE_ID, jdbcType=VARCHAR}

SELECT COUNT(1) AS CNT FROM ( SELECT BAS_YYMM ,VALT_BRNO , (SELECT DEP_TITLE FROM C_DEP_INFO WHERE DEP_DESC = VALT_BRNO) VALT_BRNM ,VALT01 ,VALT02 ,VALT03 ,(CASE WHEN VALT01 = VALT02 AND VALT01 = VALT03 THEN 'Y' ELSE 'N' END ) AS VALT04 ,GYLJ_S_C /* 결재상태코드 */ ,NVL( (SELECT DTL_C_NM FROM SRBA_DTL_C WHERE GRP_C = 'R325' AND DTL_C = GYLJ_S_C) ,'미진행') AS GYLJ_S_C_NM /* 결재상태 */ ,GYLJ_ROLE_ID ,GYLJ_ID FROM( SELECT T02.BAS_YYMM AS BAS_YYMM ,T02.VALT_BRNO AS VALT_BRNO ,COUNT(T02.BAS_YYMM) AS VALT01 ,(SELECT COUNT(*) FROM SRBA_V_TONGJE_R WHERE BAS_YYMM = T02.BAS_YYMM AND VALT_BRNO = T02.VALT_BRNO AND DSGN_VALT_PNT IS NOT NULL) AS VALT02 ,(SELECT COUNT(*) FROM SRBA_V_TONGJE_R WHERE BAS_YYMM = T02.BAS_YYMM AND VALT_BRNO = T02.VALT_BRNO AND TONGJE_VALD_PNT IS NOT NULL) AS VALT03 ,(SELECT DISTINCT GYLJ_S_C FROM SRBA_V_TONGJE_R WHERE BAS_YYMM = T02.BAS_YYMM AND VALT_BRNO = T02.VALT_BRNO) AS GYLJ_S_C ,(SELECT DISTINCT GYLJ_ID FROM SRBA_V_TONGJE_R WHERE BAS_YYMM = T02.BAS_YYMM AND VALT_BRNO = T02.VALT_BRNO) AS GYLJ_ID ,(SELECT DISTINCT GYLJ_ROLE_ID FROM SRBA_V_TONGJE_R WHERE BAS_YYMM = T02.BAS_YYMM AND VALT_BRNO = T02.VALT_BRNO) AS GYLJ_ROLE_ID FROM SRBA_V_TONGJE_R T02, SRBA_VALT_BRNO C WHERE 1=1 AND T02.BAS_YYMM = C.BAS_YYMM AND T02.VALT_BRNO = C.BRNO AND T02.BAS_YYMM = (SELECT MAX(BAS_YYMM) AS MAX_BAY_YYMM FROM SRBA_VALT_SCHD_M WHERE BAS_YYMM != '999912') GROUP BY T02.BAS_YYMM,T02.VALT_BRNO ) )AA WHERE 1=1 AND AA.VALT04 = 'Y'
AND AA.VALT_BRNO = #{VALT_BRNO, jdbcType=VARCHAR} AND (AA.GYLJ_S_C IS NULL OR AA.GYLJ_S_C IN ('0','11','22'))
AND (AA.GYLJ_ROLE_ID = #{ROLE_ID, jdbcType=VARCHAR} OR ( AA.GYLJ_S_C IN ('0','11') AND AA.VALT_BRNO = #{VALT_BRNO, jdbcType=VARCHAR}))
AND AA.GYLJ_ID <> 0 AND AA.GYLJ_ROLE_ID = #{ROLE_ID, jdbcType=VARCHAR}
AND AA.VALT_BRNO = #{VALT_BRNO, jdbcType=VARCHAR} AND AA.GYLJ_ID <> 0 AND AA.GYLJ_ROLE_ID = #{ROLE_ID, jdbcType=VARCHAR}

SELECT A.BAS_YYYY--기준년도 , A.SNO--순번 , A.SRC_TP_C--출처유형코드 , (SELECT DTL_C_NM FROM KRBA_DTL_C WHERE GRP_C = 'R311' AND DTL_C = A.SRC_TP_C) AS SRC_TP_C_NM , A.SRC_DTL_INFO--출처상세정보 , A.ML_EXP_TITE--자금세탁사례제목 , A.ML_EXP_CTNT--자금세탁사례내용 , A.RSK_CAUS_CTNT--위험원인내용 , A.REL_NAT_NM--관련국가명 , A.REL_NAT_RSK_TP_C--관련국가위험유형코드 , (SELECT RSK_EVT_NM FROM KRBA_RSK_EVT_I WHERE RSK_CATG = '1' AND RSK_EVT=A.REL_NAT_RSK_TP_C) AS REL_NAT_RSK_TP_C_NM , A.CUST_DWL_TP_C--고객주거유형코드 , (SELECT RSK_EVT_NM FROM KRBA_RSK_EVT_I WHERE RSK_CATG = '2' AND RSK_FAC ='01' AND RSK_EVT=A.CUST_DWL_TP_C) AS CUST_DWL_TP_C_NM , A.CUST_ASS_SCAL_C--고객자산규모코드 , (SELECT RSK_EVT_NM FROM KRBA_RSK_EVT_I WHERE RSK_CATG = '2' AND RSK_FAC ='02' AND RSK_EVT=A.CUST_ASS_SCAL_C) AS CUST_ASS_SCAL_C_NM , NVL(A.CUST_OCP_G_C, '09') AS CUST_OCP_G_C --고객직업구분코드 , (SELECT RSK_EVT_NM FROM KRBA_RSK_EVT_I WHERE RSK_CATG = '2' AND RSK_FAC ='03' AND RSK_EVT=NVL(A.CUST_OCP_G_C, '09')) AS CUST_OCP_G_C_NM , NVL(A.CUST_UPSL_G_C, '18') AS CUST_UPSL_G_C --고객업종구분코드 , (SELECT RSK_EVT_NM FROM KRBA_RSK_EVT_I WHERE RSK_CATG = '2' AND RSK_FAC ='04' AND RSK_EVT=NVL(A.CUST_UPSL_G_C, '18')) AS CUST_UPSL_G_C_NM , NVL(A.CUST_INDV_PCUL_C, '06') AS CUST_INDV_PCUL_C --고객개인특성코드 , (SELECT RSK_EVT_NM FROM KRBA_RSK_EVT_I WHERE RSK_CATG = '2' AND RSK_FAC ='05' AND RSK_EVT=NVL(A.CUST_INDV_PCUL_C, '06')) AS CUST_INDV_PCUL_C_NM , NVL(A.CUST_CORP_PCUL_C, '07') AS CUST_CORP_PCUL_C --고객법인특성코드 , (SELECT RSK_EVT_NM FROM KRBA_RSK_EVT_I WHERE RSK_CATG = '2' AND RSK_FAC ='06' AND RSK_EVT=NVL(A.CUST_CORP_PCUL_C, '07')) AS CUST_CORP_PCUL_C_NM , A.CUST_RELR_TP_C--고객관련자유형코드 , (SELECT RSK_EVT_NM FROM KRBA_RSK_EVT_I WHERE RSK_CATG = '2' AND RSK_FAC ='07' AND RSK_EVT=A.CUST_RELR_TP_C) AS CUST_RELR_TP_C_NM , A.PROD_LN_C--상품여신코드 , (SELECT DTL_C_NM FROM KRBA_DTL_C WHERE GRP_C = 'R312' AND DTL_C =A.PROD_LN_C) AS PROD_LN_C_NM , A.PROD_INSU_C--상품보험코드 , (SELECT DTL_C_NM FROM KRBA_DTL_C WHERE GRP_C = 'R313' AND DTL_C =A.PROD_INSU_C) AS PROD_INSU_C_NM , A.PROD_INV_C--상품투자코드 , (SELECT DTL_C_NM FROM KRBA_DTL_C WHERE GRP_C = 'R314' AND DTL_C =A.PROD_INV_C) AS PROD_INV_C_NM , A.PROD_RDAMT_G_C--상품입출금구분코드 , (SELECT DTL_C_NM FROM KRBA_DTL_C WHERE GRP_C = 'R315' AND DTL_C =A.PROD_RDAMT_G_C) AS PROD_RDAMT_G_C_NM , A.PROD_TRN_SCAL--상품거래규모 , A.PROD_TRN_PCUL_C--상품거래특성코드 , (SELECT DTL_C_NM FROM KRBA_DTL_C WHERE GRP_C = 'R316' AND DTL_C =A.PROD_TRN_PCUL_C) AS PROD_TRN_PCUL_C_NM , A.ENTR_CHNL_INSU_C--가입채널보험코드 , (SELECT RSK_EVT_NM FROM KRBA_RSK_EVT_I WHERE RSK_CATG = '4' AND RSK_FAC ='01' AND RSK_EVT=A.ENTR_CHNL_INSU_C) AS ENTR_CHNL_INSU_C_NM , A.ENTR_CHNL_LN_C--가입채널여신코드 , (SELECT RSK_EVT_NM FROM KRBA_RSK_EVT_I WHERE RSK_CATG = '4' AND RSK_FAC ='02' AND RSK_EVT=A.ENTR_CHNL_LN_C) AS ENTR_CHNL_LN_C_NM , A.PAY_CHNL_C--납입채널코드 , (SELECT RSK_EVT_NM FROM KRBA_RSK_EVT_I WHERE RSK_CATG = '4' AND RSK_FAC ='03' AND RSK_EVT=A.PAY_CHNL_C) AS PAY_CHNL_C_NM , A.REL_F_CRIM_C--관련전제범죄코드 , (SELECT DTL_C_NM FROM KRBA_DTL_C WHERE GRP_C = 'R317' AND DTL_C =A.REL_F_CRIM_C) AS REL_F_CRIM_C_NM , A.REL_FNCO_C--관련금융회사코드 , A.SSPS_TRN_TP_C--의심거래유형코드 , (SELECT DTL_C_NM FROM KRBA_DTL_C WHERE GRP_C = 'R319' AND DTL_C = A.SSPS_TRN_TP_C) AS SSPS_TRN_TP_C_NM FROM KRBA_ML_EXP_I A WHERE BAS_YYYY = #{BAS_YYYY, jdbcType=VARCHAR}
AND A.REL_F_CRIM_C = #{REL_CRIME, jdbcType=VARCHAR}
AND A.SSPS_TRN_TP_C = #{SUS_RTAN_CATE, jdbcType=VARCHAR}
AND A.SRC_TP_C = #{SRC_TP_C, jdbcType=VARCHAR}
AND A.SNO = #{SNO, jdbcType=VARCHAR}
ORDER BY A.SNO

mapper.update:
INSERT INTO KRBA_ML_EXP_I /* RBA 자금세탁사례조회 */
       (
       BAS_YYYY           /* 기준년도             */
     , SNO                /* 순번                 */
     , SRC_TP_C           /* 출처유형코드         */
     , SRC_DTL_INFO       /* 출처상세정보         */
     , ML_EXP_TITE        /* 자금세탁사례제목     */
     , ML_EXP_CTNT        /* 자금세탁사례내용     */
     , RSK_CAUS_CTNT      /* 위험원인내용         */
     , REL_NAT_NM         /* 관련국가명           */
     , REL_NAT_RSK_TP_C   /* 관련국가위험유형코드 */
     , CUST_DWL_TP_C      /* 고객주거유형코드     */
     , CUST_ASS_SCAL_C    /* 고객자산규모코드     */
     , CUST_OCP_G_C       /* 고객직업구분코드     */
     , CUST_UPSL_G_C      /* 고객업종구분코드     */
     , CUST_INDV_PCUL_C   /* 고객개인특성코드     */
     , CUST_CORP_PCUL_C   /* 고객법인특성코드     */
     , CUST_RELR_TP_C     /* 고객관련자유형코드   */
     , PROD_LN_C          /* 상품여신코드         */
     , PROD_INSU_C        /* 상품보험코드         */
     , PROD_INV_C         /* 상품투자코드         */
     , PROD_RDAMT_G_C     /* 상품입출금구분코드   */
     , PROD_TRN_SCAL      /* 상품거래규모         */
     , PROD_TRN_PCUL_C    /* 상품거래특성코드     */
     , ENTR_CHNL_INSU_C   /* 가입채널보험코드     */
     , ENTR_CHNL_LN_C     /* 가입채널여신코드     */
     , PAY_CHNL_C         /* 납입채널코드         */
     , REL_F_CRIM_C       /* 관련전제범죄코드     */
     , REL_FNCO_C         /* 관련금융회사코드     */
     , SSPS_TRN_TP_C      /* 의심거래유형코드     */
       )
VALUES
       (
       #{BAS_YYYY,jdbcType=VARCHAR}
     , (SELECT (NVL(MAX(SNO), 0) + 1) FROM KRBA_ML_EXP_I WHERE BAS_YYYY = #{BAS_YYYY,jdbcType=VARCHAR})
     , #{SRC_TP_C,jdbcType=VARCHAR}
     , #{SRC_DTL_INFO,jdbcType=VARCHAR}
     , #{ML_EXP_TITE,jdbcType=VARCHAR}
     , #{ML_EXP_CTNT,jdbcType=VARCHAR}
     , #{RSK_CAUS_CTNT,jdbcType=VARCHAR}
     , #{REL_NAT_NM,jdbcType=VARCHAR}
     , #{REL_NAT_RSK_TP_C,jdbcType=VARCHAR}
     , #{CUST_DWL_TP_C,jdbcType=VARCHAR}
     , #{CUST_ASS_SCAL_C,jdbcType=VARCHAR}
     , #{CUST_OCP_G_C,jdbcType=VARCHAR}
     , #{CUST_UPSL_G_C,jdbcType=VARCHAR}
     , #{CUST_INDV_PCUL_C,jdbcType=VARCHAR}
     , #{CUST_CORP_PCUL_C,jdbcType=VARCHAR}
     , #{CUST_RELR_TP_C,jdbcType=VARCHAR}
     , #{PROD_LN_C,jdbcType=VARCHAR}
     , #{PROD_INSU_C,jdbcType=VARCHAR}
     , #{PROD_INV_C,jdbcType=VARCHAR}
     , #{PROD_RDAMT_G_C,jdbcType=VARCHAR}
