SELECT /* RBA_30.RBA_30_04_01_01_doSearch */ A.BAS_YYYY AS BAS_YYYY /* 기준연도 */ , A.TONGJE_ACT_ID AS TONGJE_ACT_ID /* 통제활동ID */ , A.CH_ID AS CH_ID /* 취약점ID */ , B.TONGJE_FLD_C AS TONGJE_FLD_C /* 통제영역코드 */ , (SELECT DTL_C_NM FROM KRBA_DTL_C WHERE GRP_C = 'R308' AND DTL_C = B.TONGJE_FLD_C) AS TONGJE_FLD_C_NM /* 통제영역코드명 */ , B.TONGJE_PROC_C AS TONGJE_PROC_C /* 통제프로세스코드 */ , (SELECT DTL_C_NM FROM KRBA_DTL_C WHERE GRP_C = 'R309' AND DTL_C = B.TONGJE_PROC_C) AS TONGJE_PROC_C_NM /* 통제프로세스코드명 */ , B.TONGJE_SUB_PROC_C AS TONGJE_SUB_PROC_C /* 통제서브프로세스코드 */ , (SELECT DTL_C_NM FROM KRBA_DTL_C WHERE GRP_C = 'R310' AND DTL_C = B.TONGJE_SUB_PROC_C) AS TONGJE_SUB_PROC_C_NM /* 통제서브프로세스코드명 */ , A.TONGJE_ACT_TITE AS TONGJE_ACT_TITE /* 통제활동제목 */ , A.TONGJE_ACT_DTL AS TONGJE_ACT_DTL /* 통제활동상세 */ , A.IMPRV_YN AS IMPRV_YN /* 취약점등록여부 */ , A.FIX_YN AS FIX_YN /* 확정여부 */ , A.DSGN_VALT_BRNO AS DSGN_VALT_BRNO /* 설계평가부점번호 */ , (SELECT DPRT_NM FROM NIC41B WHERE DPRT_CD = A.DSGN_VALT_BRNO) AS DSGN_VALT_BR_NM /* 설계평가부점명 */ , A.DSGN_VALD_RT AS DSGN_VALD_RT /* 설계유효성비율 */ , A.USYN AS USYN /* 사용여부 */ , (SELECT COUNT(1) FROM KRBA_EXPS_LST_I WHERE BAS_YYYY = #{BAS_YYYY, jdbcType=VARCHAR}) AS EXPS_CNT /* 노출위험건수 */ FROM KRBA_TJ_ACT_M A /* RBA 통제활동 */ JOIN KRBA_INTJ_CH_M B /* RBA 내부통제 취약점 */ ON A.BAS_YYYY = B.BAS_YYYY AND A.CH_ID = B.CH_ID WHERE 1=1 AND A.BAS_YYYY = #{BAS_YYYY, jdbcType=VARCHAR}
AND B.TONGJE_FLD_C = #{TONGJE_FLD_C, jdbcType=VARCHAR}
AND B.TONGJE_PROC_C = #{TONGJE_PROC_C, jdbcType=VARCHAR}
AND B.TONGJE_SUB_PROC_C = #{TONGJE_SUB_PROC_C, jdbcType=VARCHAR}
AND A.DSGN_VALT_BRNO = #{DSGN_VALT_BRNO, jdbcType=VARCHAR}
AND A.USYN = 1 AND A.FIX_YN = 0
ORDER BY A.CH_ID, CAST(SUBSTR(A.TONGJE_ACT_ID, LENGTH(A.CH_ID) + 3, 2) AS INTEGER) -- for Oracle -- ORDER BY A.CH_ID, TO_NUMBER(SUBSTR(A.TONGJE_ACT_ID, LENGTH(A.CH_ID) + 3, 2))

SELECT /* RBA_30.RBA_30_04_01_01_doDownload */ A.BAS_YYYY AS BAS_YYYY /* 기준연도 */ , A.TONGJE_ACT_ID AS TONGJE_ACT_ID /* 통제활동ID */ , A.CH_ID AS CH_ID /* 취약점ID */ , B.TONGJE_FLD_C AS TONGJE_FLD_C /* 통제영역코드 */ , (SELECT DTL_C_NM FROM KRBA_DTL_C WHERE GRP_C = 'R308' AND DTL_C = B.TONGJE_FLD_C) AS TONGJE_FLD_C_NM /* 통제영역코드명 */ , B.TONGJE_PROC_C AS TONGJE_PROC_C /* 통제프로세스코드 */ , (SELECT DTL_C_NM FROM KRBA_DTL_C WHERE GRP_C = 'R309' AND DTL_C = B.TONGJE_PROC_C) AS TONGJE_PROC_C_NM /* 통제프로세스코드명 */ , B.TONGJE_SUB_PROC_C AS TONGJE_SUB_PROC_C /* 통제서브프로세스코드 */ , (SELECT DTL_C_NM FROM KRBA_DTL_C WHERE GRP_C = 'R310' AND DTL_C = B.TONGJE_SUB_PROC_C) AS TONGJE_SUB_PROC_C_NM /* 통제서브프로세스코드명 */ , A.TONGJE_ACT_TITE AS TONGJE_ACT_TITE /* 통제활동제목 */ , A.TONGJE_ACT_DTL AS TONGJE_ACT_DTL /* 통제활동상세 */ , A.BIZ_RULE_REL_ITEM AS BIZ_RULE_REL_ITEM /* 업무규정관련항목 */ , A.REL_DATA_CTNT AS REL_DATA_CTNT /* 관련자료내용 */ , A.TONGJE_APPL_SCOP_C AS TONGJE_APPL_SCOP_C /* 통제적용범위코드 */ , (SELECT DTL_C_NM FROM KRBA_DTL_C WHERE GRP_C = 'R324' AND DTL_C = A.TONGJE_APPL_SCOP_C) AS TONGJE_APPL_SCOP_C_NM /* 통제적용범위코드명 */ , A.TONGJE_TP_C AS TONGJE_TP_C /* 통제유형코드 */ , (SELECT DTL_C_NM FROM KRBA_DTL_C WHERE GRP_C = 'R325' AND DTL_C = A.TONGJE_TP_C) AS TONGJE_TP_C_NM /* 통제적용범위코드명 */ , A.DSGN_VALT_BRNO AS DSGN_VALT_BRNO /* 설계평가부점번호 */ , (SELECT DPRT_NM FROM NIC41B WHERE DPRT_CD = A.DSGN_VALT_BRNO) AS DSGN_VALT_BR_NM /* 설계평가부점명 */ , A.AIM_STTP_RT AS AIM_STTP_RT /* 목적적합성비율 */ , A.OPR_POSS_RT AS OPR_POSS_RT /* 운영가능성비율 */ , A.DSGN_VALD_RT AS DSGN_VALD_RT /* 설계유효성비율 */ , A.USYN AS USYN /* 사용여부 */ , CASE WHEN A.USYN = 1 THEN 'Y' WHEN A.USYN = 0 THEN 'N' END AS USYN_NM /* 사용여부 */ FROM KRBA_TJ_ACT_M A /* RBA 통제활동 */ JOIN KRBA_INTJ_CH_M B /* RBA 내부통제 취약점 */ ON A.BAS_YYYY = B.BAS_YYYY AND A.CH_ID = B.CH_ID WHERE 1=1 AND A.BAS_YYYY = #{BAS_YYYY, jdbcType=VARCHAR}
AND B.TONGJE_FLD_C = #{TONGJE_FLD_C, jdbcType=VARCHAR}
AND B.TONGJE_PROC_C = #{TONGJE_PROC_C, jdbcType=VARCHAR}
AND B.TONGJE_SUB_PROC_C = #{TONGJE_SUB_PROC_C, jdbcType=VARCHAR}
AND A.DSGN_VALT_BRNO = #{DSGN_VALT_BRNO, jdbcType=VARCHAR}
AND A.USYN = 1 AND A.FIX_YN = 0
ORDER BY A.CH_ID, CAST(SUBSTR(A.TONGJE_ACT_ID, LENGTH(A.CH_ID) + 3, 2) AS INTEGER) -- for Oracle -- ORDER BY A.CH_ID, TO_NUMBER(SUBSTR(A.TONGJE_ACT_ID, LENGTH(A.CH_ID) + 3, 2))

