SELECT /* RBA_30.RBA_30_04_01_05_doSearch */ D.DTL_NM AS JIPYO_PNT_NM , E.DTL_NM AS INC_V_C_NM , F.DTL_NM AS JIPYO_C_NM , G.DTL_NM AS JIPYO_FLD_C_NM , H.DTL_NM AS JIPYO_SUB_FLD_C_NM , A.JIPYO_C , A.JIPYO_FLD_C , A.JIPYO_SUB_FLD_C , A.RPT_GJDT , A.JIPYO_ID , A.JIPYO_USYN , A.JIPYO_NM , A.JIPYO_PNT , A.UNIT_CTNT , A.EVAL_GUBUN , A.ATTCH_FILE_YN , A.ATTCH_FILE_ALLT_YN , A.VALT_V_K , A.IN_V_WRT_G , A.OBJ_V_CNFG_YN , A.CALC_MTH_CTNT , A.CALC_GJ , A.VALT_BAS_CTNT , A.PGM_NM , A.MEMO , A.JIPYO_BIGO_CTNT , B.VALT_PNT , C.IN_V FROM RBA200TB A LEFT JOIN RBA250TB B ON A.RPT_GJDT = B.RPT_GJDT AND A.JIPYO_ID = B.JIPYO_ID LEFT JOIN RBA270TB C ON A.RPT_GJDT = C.RPT_GJDT AND A.JIPYO_ID = C.JIPYO_ID AND C.SNO = '1' AND C.CHILD_SNO = '1' LEFT OUTER JOIN RBA030TB D ON A.RPT_GJDT = D.RPT_GJDT AND A.JIPYO_PNT = D.DTL_CD AND D.GRP_CD = 'A0004' LEFT OUTER JOIN RBA030TB E ON A.RPT_GJDT = E.RPT_GJDT AND A.INC_V_C = E.DTL_CD AND E.GRP_CD = 'A0007' LEFT OUTER JOIN RBA030TB F ON A.RPT_GJDT = F.RPT_GJDT AND A.JIPYO_C = F.DTL_CD AND F.GRP_CD = 'A0001' LEFT OUTER JOIN RBA030TB G ON A.RPT_GJDT = G.RPT_GJDT AND A.JIPYO_FLD_C = G.DTL_CD AND G.GRP_CD = 'C0036' LEFT OUTER JOIN RBA030TB H ON A.RPT_GJDT = H.RPT_GJDT AND A.JIPYO_SUB_FLD_C = H.DTL_CD AND H.GRP_CD = 'C0037' WHERE 1=1
AND A.RPT_GJDT = #{RPT_GJDT, jdbcType=VARCHAR}
