SELECT /* RBA_30.RBA_30_04_02_01_doSearch */ A.BAS_YYYY AS BAS_YYYY /* 기준연도 */ , #{DSGN_VALT_BRNO, jdbcType=VARCHAR} AS DSGN_VALT_BRNO /* 설계평가부점번호 */ , CASE WHEN GROUPING(C.DTL_C_NM) = 1 THEN '' ELSE B.TONGJE_FLD_C END AS TONGJE_FLD_C /* 통제영역코드 */ , CASE WHEN GROUPING(C.DTL_C_NM) = 1 THEN '전체 합계 / 평균' ELSE C.DTL_C_NM END AS TONGJE_FLD_C_NM /* 통제영역코드명 */ , CASE WHEN GROUPING(C.DTL_C_NM) = 1 AND GROUPING(D.DTL_C_NM) = 1 THEN '' WHEN GROUPING(D.DTL_C_NM) = 1 THEN '영역별 합계 / 평균' ELSE B.TONGJE_PROC_C END AS TONGJE_PROC_C /* 통제프로세스코드 */ , CASE WHEN GROUPING(D.DTL_C_NM) = 1 THEN '' ELSE D.DTL_C_NM END AS TONGJE_PROC_C_NM /* 통제프로세스코드명 */ , SUM(CASE WHEN A.TONGJE_APPL_SCOP_C = '1' THEN 1 ELSE 0 END) AS TONGJE_APPL_SCOP_1_CNT /* 통제적용범위코드1(전사)건수 */ , SUM(CASE WHEN A.TONGJE_APPL_SCOP_C = '2' THEN 1 ELSE 0 END) AS TONGJE_APPL_SCOP_2_CNT /* 통제적용범위코드2(부점)건수 */ , COUNT(A.TONGJE_APPL_SCOP_C) AS TOT_TONGJE_APPL_SCOP_C_CNT /* 총통제적용범위코드건수 */ , ROUND(AVG(AIM_STTP_RT)) AS AVG_AIM_STTP_RT /* 평균목적적합성비율 */ , ROUND(AVG(OPR_POSS_RT)) AS AVG_OPR_POSS_RT /* 평균운영가능성비율 */ , ROUND((ROUND(AVG(AIM_STTP_RT)) + ROUND(AVG(OPR_POSS_RT))) / 2) AS AVG_TOT_RT /* 평균총비율 */ FROM KRBA_TJ_ACT_M A /* RBA 통제활동 */ JOIN KRBA_INTJ_CH_M B /* RBA 내부통제 취약점 */ ON A.BAS_YYYY = B.BAS_YYYY AND A.CH_ID = B.CH_ID AND A.USYN = 1 AND A.FIX_YN = 1 JOIN KRBA_DTL_C C /* RBA 상세코드_R308 */ ON B.TONGJE_FLD_C = C.DTL_C AND C.GRP_C = 'R308' /* R308:통제영역 */ JOIN KRBA_DTL_C D /* RBA 상세코드_R309 */ ON B.TONGJE_PROC_C = D.DTL_C AND D.GRP_C = 'R309' /* R309:통제프로세스 */ WHERE 1=1 AND A.BAS_YYYY = #{BAS_YYYY, jdbcType=VARCHAR}
AND A.DSGN_VALT_BRNO = #{DSGN_VALT_BRNO, jdbcType=VARCHAR}
GROUP BY ROLLUP ((A.BAS_YYYY, B.TONGJE_FLD_C, C.DTL_C_NM), (B.TONGJE_PROC_C, D.DTL_C_NM)) ORDER BY A.BAS_YYYY, B.TONGJE_FLD_C, B.TONGJE_PROC_C

SELECT /* RBA_30.RBA_30_04_03_01_doSearch */ A.BAS_YYYY AS BAS_YYYY /* 기준년도 */ , A.TONGJE_OPR_VALT_ID AS TONGJE_OPR_VALT_ID /* 통제운영평가ID */ , A.VALT_TRN AS VALT_TRN /* 평가회차 */ , A.VALT_BRNO AS VALT_BRNO /* 평가부점 */ , A.TONGJE_ACT_ID AS TONGJE_ACT_ID /* 통제활동ID */ , A.CH_ID AS CH_ID /* 취약점ID */ , A.TONGJE_FLD_C AS TONGJE_FLD_C /* 통제영역코드 */ , (SELECT DTL_C_NM FROM KRBA_DTL_C WHERE GRP_C = 'R308' AND DTL_C = A.TONGJE_FLD_C) AS TONGJE_FLD_C_NM /* 통제영역코드명 */ , A.TONGJE_PROC_C AS TONGJE_PROC_C /* 통제프로세스코드 */ , (SELECT DTL_C_NM FROM KRBA_DTL_C WHERE GRP_C = 'R309' AND DTL_C = A.TONGJE_PROC_C) AS TONGJE_PROC_C_NM /* 통제프로세스코드명 */ , A.TONGJE_SUB_PROC_C AS TONGJE_SUB_PROC_C /* 통제서브프로세스코드 */ , (SELECT DTL_C_NM FROM KRBA_DTL_C WHERE GRP_C = 'R310' AND DTL_C = A.TONGJE_SUB_PROC_C) AS TONGJE_SUB_PROC_C_NM /* 통제서브프로세스코드명 */ , B.TONGJE_ACT_TITE AS TONGJE_ACT_TITE /* 통제활동제목 */ , B.TONGJE_TP_C AS TONGJE_TP_C /* 통제유형코드 */ , (SELECT DTL_C_NM FROM KRBA_DTL_C WHERE GRP_C = 'R325' AND DTL_C = B.TONGJE_TP_C) AS TONGJE_TP_C_NM /* 통제유형코드명 */ , C.VALT_METH_CTNT AS VALT_METH_CTNT /* 평가방법내용 */ , A.OPR_EFF_RT AS OPR_EFF_RT /* 운영효과성비율 */ , A.TONGJE_EFF_RT AS TONGJE_EFF_RT /* 통제효과성비율 */ , A.TP_ATTCH_FILE_NO AS TP_ATTCH_FILE_NO /* 템플릿첨부파일번호 */ , A.MNGR_JKW_NO AS MNGR_JKW_NO /* 담당자직원번호 */ , (SELECT USER_NM FROM C_USER WHERE LOGIN_ID = A.MNGR_JKW_NO) AS MNGR_JKW_NM /* 담당자직원명 */ , A.FIX_YN AS FIX_YN /* 확정여부 */ , A.FIX_DT AS FIX_DT /* 확정일자 */ , A.FIX_JKW_NO AS FIX_JKW_NO /* 확정자직원번호 */ , A.IMPRV_YN AS IMPRV_YN /* 개선여부 */ , A.GYLJ_S_C AS GYLJ_S_C /* 결재상태코드 */ , (SELECT DTL_C_NM FROM KRBA_DTL_C WHERE GRP_C = 'R323' AND DTL_C = A.GYLJ_S_C) AS GYLJ_S_C_NM /* 결재상태코드명 */ , A.GYLJ_DT AS GYLJ_DT /* 결재일자 */ , A.GYLJ_JKW_NO AS GYLJ_JKW_NO /* 결재직원번호 */ , A.GYLJ_ID AS GYLJ_ID /* 결재ID */ , C.OPR_VALT_TP_C AS OPR_VALT_TP_C /* 운영평가TYPE코드 */ , (SELECT D.VALT_EDT FROM KRBA_VALT_SCHD_D D WHERE 1=1 AND D.BAS_YYYY = A.BAS_YYYY AND D.RSK_MNG_ACT_C = '4' /* R301 4:통제활동 운영 효과성 평가 */ AND D.RSK_MNG_ACT_DTL_C = '4.1' /* R302 4.1:통제활동 운영 평가 */ AND D.VALT_TRN = A.VALT_TRN) AS VALT_EDT /* 평가기한 */ , (SELECT E.REAL_EDT FROM KRBA_VALT_SCHD_D E WHERE 1=1 AND E.BAS_YYYY = A.BAS_YYYY AND E.RSK_MNG_ACT_C = '4' /* R301 4:통제활동 운영 효과성 평가 */ AND E.RSK_MNG_ACT_DTL_C = '4.2' /* R302 4.2:통제활동 운영 취약점 개선 */ AND E.VALT_TRN = A.VALT_TRN) AS REAL_EDT_4_2 /* 운영 취약점 실제종료일 */ FROM KRBA_BRNO_VALT_M A /* RBA 부점별 통제운영평가 */ JOIN KRBA_TJ_ACT_M B /* RBA 통제활동 */ ON A.BAS_YYYY = B.BAS_YYYY AND A.TONGJE_ACT_ID = B.TONGJE_ACT_ID JOIN KRBA_TJ_OP_VALT_M C /* RBA 통제운영평가 */ ON A.BAS_YYYY = C.BAS_YYYY AND A.TONGJE_OPR_VALT_ID = C.TONGJE_OPR_VALT_ID WHERE 1=1 AND A.BAS_YYYY = #{BAS_YYYY, jdbcType=VARCHAR} AND A.VALT_TRN = #{VALT_TRN, jdbcType=NUMERIC}
AND A.TONGJE_FLD_C = #{TONGJE_FLD_C, jdbcType=VARCHAR}
AND A.TONGJE_PROC_C = #{TONGJE_PROC_C, jdbcType=VARCHAR}
AND A.GYLJ_S_C = #{GYLJ_S_C, jdbcType=VARCHAR}
AND A.VALT_BRNO = #{VALT_BRNO, jdbcType=VARCHAR}
AND A.VALT_BRNO = #{VALT_BRNO, jdbcType=VARCHAR} AND (A.GYLJ_S_C IS NULL OR A.GYLJ_S_C IN ('0','11','12','22'))
AND A.VALT_BRNO = #{VALT_BRNO, jdbcType=VARCHAR} AND (A.GYLJ_S_C IS NULL OR A.GYLJ_S_C IN ('0','11','12','22'))
AND A.VALT_BRNO = #{VALT_BRNO, jdbcType=VARCHAR} AND A.GYLJ_ID <> 0 AND A.GYLJ_S_C = '21'
AND A.VALT_BRNO = #{VALT_BRNO, jdbcType=VARCHAR} AND A.GYLJ_ID <> 0 AND A.GYLJ_S_C = '21'
AND A.MNGR_JKW_NO = #{MNGR_JKW_NO, jdbcType=VARCHAR} AND (A.GYLJ_S_C IS NULL OR A.GYLJ_S_C IN ('0','11','12','22'))
ORDER BY A.BAS_YYYY, A.VALT_TRN, A.VALT_BRNO, A.CH_ID, CAST(SUBSTR(A.TONGJE_ACT_ID, LENGTH(A.CH_ID) + 3, 2) AS INTEGER) -- for Oracle -- ORDER BY A.BAS_YYYY, A.VALT_TRN, A.VALT_BRNO, A.CH_ID, TO_NUMBER(SUBSTR(A.TONGJE_ACT_ID, LENGTH(A.CH_ID) + 3, 2))

