SELECT /* RBA_30.RBA_30_04_04_01_doSearch */ CASE WHEN GROUPING(A.TONGJE_FLD_C ||'.'||B.DTL_C_NM) = 1 AND GROUPING(A.TONGJE_PROC_C ||'.'|| C.DTL_C_NM) = 1 THEN ' 전체 합계 / 전체 평균' ELSE A.TONGJE_FLD_C ||'.'||B.DTL_C_NM END AS TONGJE_FLD_C_NM /* 영역 */ , CASE WHEN GROUPING(A.TONGJE_FLD_C ||'.'||B.DTL_C_NM) = 1 AND GROUPING(A.TONGJE_PROC_C ||'.'|| C.DTL_C_NM) = 1 THEN '' WHEN GROUPING(A.TONGJE_PROC_C ||'.'|| C.DTL_C_NM) = 1 THEN ' 영역별 합계 / 영역별 효과성 평균' ELSE A.TONGJE_PROC_C ||'.'|| C.DTL_C_NM END AS TONGJE_PROC_C_NM /* Process */ , COUNT(DISTINCT(A.TONGJE_OPR_VALT_ID)) AS TONGJE_ACT_CNT /* 통제활동 수 */ , ROUND(AVG(A.TONGJE_EFF_RT)) AS DSGN_VALD_RT /* 통제운영효과성 */ FROM KRBA_BRNO_VALT_M A /* RBA 부점별 통제운영평가 */ LEFT OUTER JOIN KRBA_DTL_C B /* RBA 상세코드 */ ON A.TONGJE_FLD_C = B.DTL_C AND B.GRP_C = 'R308' /* 그룹코드(R308:통제영역) */ LEFT OUTER JOIN KRBA_DTL_C C /* RBA 상세코드 */ ON A.TONGJE_PROC_C = C.DTL_C AND C.GRP_C = 'R309' /* 그룹코드(R309:통제프로세스) */ WHERE 1=1 AND A.BAS_YYYY = #{BAS_YYYY, jdbcType=VARCHAR}
AND A.VALT_TRN = #{VALT_TRN, jdbcType=NUMERIC}
AND A.VALT_BRNO = #{VALT_BRNO, jdbcType=VARCHAR}
GROUP BY ROLLUP(A.TONGJE_FLD_C ||'.'||B.DTL_C_NM, A.TONGJE_PROC_C ||'.'|| C.DTL_C_NM) ORDER BY A.TONGJE_FLD_C ||'.'||B.DTL_C_NM, A.TONGJE_PROC_C ||'.'|| C.DTL_C_NM

SELECT /* RBA_30.RBA_30_04_05_01_doSearch */ A.BAS_YYYY AS BAS_YYYY /* 기준년도 */ , A.VALT_TRN AS VALT_TRN /* 평가부점 */ , A.VALT_BRNO AS VALT_BRNO /* 통제활동ID */ , C.DPRT_NM AS DPRT_NM /* 부점명 */ , COUNT(A.TONGJE_OPR_VALT_ID) AS VALT_CNT /* 평가건수 */ , SUM(CASE WHEN A.FIX_YN = 0 THEN 1 ELSE 0 END) AS RDY_CNT /* 미진행건수 */ , SUM(CASE WHEN A.FIX_YN = 1 THEN 1 ELSE 0 END) AS CNF_CNT /* 평가완료건수 */ , SUM(CASE WHEN A.IMPRV_YN = 1 THEN 1 ELSE 0 END) AS CH_CNT /* 취약점건수 */ , SUM(CASE WHEN A.GYLJ_ID = 0 AND A.GYLJ_S_C <> '3' THEN 1 ELSE 0 END) AS ING_CNT /* 마감대상건수 */ , SUM(CASE WHEN A.GYLJ_S_C = '3' THEN 1 ELSE 0 END) AS CPT_CNT /* 승인완료건수 */ , SUM(CASE WHEN A.GYLJ_S_C = '22' THEN 1 ELSE 0 END) AS REJ_CNT /* 반려건수 */ , ROUND(SUM(CASE WHEN A.FIX_YN = 1 THEN 1 ELSE 0 END) / COUNT(A.TONGJE_OPR_VALT_ID) * 100, 0) AS CPT_RT /* 평가완료율 */ , ROUND(SUM(CASE WHEN A.GYLJ_S_C = '3' THEN 1 ELSE 0 END) / COUNT(A.TONGJE_OPR_VALT_ID) * 100, 0) AS APR_RT /* 승인율 */ FROM KRBA_BRNO_VALT_M A /* RBA 부점별 통제운영평가 */ JOIN KRBA_TJ_ACT_M B /* RBA 통제활동 */ ON A.BAS_YYYY = B.BAS_YYYY AND A.TONGJE_ACT_ID = B.TONGJE_ACT_ID AND B.USYN = 1 LEFT OUTER JOIN NIC41B C /* AML부점_NIC41B */ ON A.VALT_BRNO = C.DPRT_CD WHERE 1=1 AND A.BAS_YYYY = #{BAS_YYYY, jdbcType=VARCHAR}
AND A.VALT_TRN = #{VALT_TRN, jdbcType=NUMERIC}
AND A.VALT_BRNO = #{VALT_BRNO, jdbcType=VARCHAR}
GROUP BY A.BAS_YYYY, A.VALT_TRN, A.VALT_BRNO, C.DPRT_NM ORDER BY A.VALT_BRNO

mapper.update:
UPDATE /* RBA_30.RBA_30_04_05_01_updateDsgnValtRealEdt */
       KRBA_VALT_SCHD_D A   /* RBA 위험평가 상세일정 */
   SET A.REAL_EDT           = #{REAL_EDT, jdbcType=VARCHAR}
     , A.CHG_DT             = #{CHG_DT, jdbcType=VARCHAR}
     , A.CHG_TIME           = #{CHG_TIME, jdbcType=VARCHAR}
     , A.CHG_OP_JKW_NO      = #{CHG_OP_JKW_NO, jdbcType=VARCHAR}
 WHERE 1=1
   AND A.BAS_YYYY           = #{BAS_YYYY, jdbcType=VARCHAR}
   AND A.VALT_TRN           = #{VALT_TRN, jdbcType=NUMERIC}
   AND ((A.RSK_MNG_ACT_C    = '4' AND A.RSK_MNG_ACT_DTL_C = '4.1')
        OR (A.RSK_MNG_ACT_C = '5' AND A.RSK_MNG_ACT_DTL_C = '5.1')

        OR (A.RSK_MNG_ACT_C = '5' AND A.RSK_MNG_ACT_DTL_C = '5.2')


        OR (A.RSK_MNG_ACT_C = '5' AND A.RSK_MNG_ACT_DTL_C = '5.3')

       )

UPDATE /* RBA_30.RBA_30_04_05_02_doSave */
       KRBA_BRNO_VALT_M A   /* RBA 부점별 통제운영평가 */
   SET A.FIX_YN             = #{FIX_YN, jdbcType=NUMERIC}
     , A.FIX_DT             = #{FIX_DT, jdbcType=VARCHAR}
     , A.FIX_JKW_NO         = #{FIX_JKW_NO, jdbcType=VARCHAR}
     , A.GYLJ_S_C           = '3'
     , A.OPR_EFF_RT         = #{OPR_EFF_RT, jdbcType=NUMERIC}
     , A.TONGJE_EFF_RT      = ROUND((#{OPR_EFF_RT, jdbcType=NUMERIC} * #{DSGN_VALD_RT, jdbcType=NUMERIC}) / 100)
     , A.CHG_DT             = #{CHG_DT, jdbcType=VARCHAR}
     , A.CHG_TIME           = #{CHG_TIME, jdbcType=VARCHAR}
     , A.CHG_OP_JKW_NO      = #{CHG_OP_JKW_NO, jdbcType=VARCHAR}
 WHERE 1=1
   AND A.BAS_YYYY           = #{BAS_YYYY, jdbcType=VARCHAR}
   AND A.TONGJE_OPR_VALT_ID = #{TONGJE_OPR_VALT_ID, jdbcType=VARCHAR}
   AND A.VALT_TRN           = #{VALT_TRN, jdbcType=NUMERIC}
   AND A.VALT_BRNO          = #{VALT_BRNO, jdbcType=VARCHAR}

