SELECT /* RBA_30.RBA_30_04_07_01_doSearch */ A.BAS_YYYY AS BAS_YYYY /* 기준년도 */ , A.DSGN_VALT_BRNO AS DSGN_VALT_BRNO /* 설계평가부점번호 */ , B.DPRT_NM AS DPRT_NM /* 평가부점 */ , COUNT(TONGJE_ACT_ID) AS VALT_CNT /* 평가건수 */ , SUM(CASE WHEN A.FIX_YN = 0 THEN 1 ELSE 0 END) AS RDY_CNT /* 미진행건수 */ , SUM(CASE WHEN A.FIX_YN = 1 THEN 1 ELSE 0 END) AS CNF_CNT /* 평가완료건수 */ , SUM(CASE WHEN A.IMPRV_YN = 1 THEN 1 ELSE 0 END) AS CH_CNT /* 취약점건수 */ FROM KRBA_TJ_ACT_M A /* RBA 통제활동 */ LEFT OUTER JOIN NIC41B B /* AML부점_NIC41B */ ON A.DSGN_VALT_BRNO = B.DPRT_CD WHERE 1=1 AND A.USYN = 1 AND A.BAS_YYYY = #{BAS_YYYY, jdbcType=VARCHAR}
AND A.DSGN_VALT_BRNO = #{DSGN_VALT_BRNO, jdbcType=VARCHAR}
GROUP BY A.BAS_YYYY, A.DSGN_VALT_BRNO, B.DPRT_NM ORDER BY A.DSGN_VALT_BRNO

