UPDATE /* RBA_30.RBA_30_04_07_01_updateDsgnValtRealEdt */
       KRBA_VALT_SCHD_D A   /* RBA 위험평가 상세일정 */
   SET A.REAL_EDT           = #{REAL_EDT, jdbcType=VARCHAR}
     , A.CHG_DT             = #{CHG_DT, jdbcType=VARCHAR}
     , A.CHG_TIME           = #{CHG_TIME, jdbcType=VARCHAR}
     , A.CHG_OP_JKW_NO      = #{CHG_OP_JKW_NO, jdbcType=VARCHAR}
 WHERE 1=1
   AND A.BAS_YYYY           = #{BAS_YYYY, jdbcType=VARCHAR}
   AND ((A.RSK_MNG_ACT_C    = '2' AND A.RSK_MNG_ACT_DTL_C = '2.4')
        OR (A.RSK_MNG_ACT_C = '3' AND A.RSK_MNG_ACT_DTL_C = '3.1'))
   AND A.VALT_TRN           = 0

	UPDATE /* RBA_30.RBA_30_04_07_02_doSave */
	       KRBA_TJ_ACT_M A /* RBA 통제활동 */
	   SET A.AIM_STTP_RT   = #{AIM_STTP_RT, jdbcType=NUMERIC}
            , A.OPR_POSS_RT   = #{OPR_POSS_RT, jdbcType=NUMERIC}
            , A.DSGN_VALD_RT  = #{DSGN_VALD_RT, jdbcType=NUMERIC}
            , A.FIX_YN        = #{FIX_YN, jdbcType=NUMERIC}
            , A.FIX_DT        = #{FIX_DT, jdbcType=VARCHAR}
            , A.FIX_JKW_NO    = #{FIX_JKW_NO, jdbcType=VARCHAR}
	     , A.CHG_DT        = #{CHG_DT, jdbcType=VARCHAR}
	     , A.CHG_TIME      = #{CHG_TIME, jdbcType=VARCHAR}
	     , A.CHG_OP_JKW_NO = #{CHG_OP_JKW_NO, jdbcType=VARCHAR}
	 WHERE 1=1
	   AND A.BAS_YYYY      = #{BAS_YYYY, jdbcType=VARCHAR}
	   AND A.TONGJE_ACT_ID = #{TONGJE_ACT_ID, jdbcType=VARCHAR}

