SELECT ROW_NUMBER() OVER (ORDER BY A.RSK_CATG, A.RSK_EVT, A.RSK_INDCT ) AS CNT --순번 , B.RSK_CATG_NM , (SELECT DTL_C_NM FROM KRBA_DTL_C WHERE GRP_C='R332' AND DTL_C = NVL(C.RSK_LVL_C, 1))||'위험' AS RSK_LVL_C , D.RSK_EVT_NM , C.RSK_EVT_CTNT , A.RSK_INDCT -- 지표ID , A.RSK_INDCT_NM , A.EXTR_BAS_AMT FROM KRBA_KRI_M A JOIN KRBA_RSK_CATG_I B ON A.RSK_CATG = B.RSK_CATG JOIN KRBA_RSK_EVT_M C ON A.RSK_CATG = C.RSK_CATG AND A.RSK_FAC = C.RSK_FAC AND A.RSK_EVT = C.RSK_EVT JOIN KRBA_RSK_EVT_I D ON A.RSK_CATG = D.RSK_CATG AND A.RSK_FAC = D.RSK_FAC AND A.RSK_EVT = D.RSK_EVT WHERE 1=1 AND C.BAS_YYYY = #{BAS_YYYY}
AND C.RSK_LVL_C = #{Risk_Level}
AND C.RSK_CATG = #{CA}
AND C.RSK_FAC = #{FA}
AND C.RSK_EVT = #{EV}
ORDER BY A.RSK_CATG, A.RSK_EVT, A.RSK_INDCT

