UPDATE KRBA_KRI_M
SET EXTR_BAS_AMT = #{EXTR_BAS_AMT}
    ,CNFR_ACTN_CTNT = #{CNFR_ACTN_CTNT}
WHERE RSK_INDCT = #{RSK_INDCT}

