SELECT (SELECT RSK_CATG_NM FROM KRBA_RSK_CATG_I WHERE RSK_CATG = A.RSK_CATG) RSK_CATG --위험카테고리 ,(SELECT RSK_EVT_NM FROM KRBA_RSK_EVT_I WHERE RSK_CATG=B.RSK_CATG AND RSK_FAC=B.RSK_FAC AND RSK_EVT=B.RSK_EVT) AS RSK_EVT_NM --위험이벤트 ,B.RSK_INDCT_NM --위험지표명 ,A.INDE_RT --증감율 ,(SELECT DTL_C_NM FROM KRBA_DTL_C WHERE GRP_C='R335' AND DTL_C=C.RSK_GD_C) AS RSK_GD_C --위험등급코드 FROM KRBA_KRI_D A ,KRBA_KRI_M B ,KRBA_KRI_BRNO_D C WHERE A.RSK_INDCT = B.RSK_INDCT AND A.RSK_INDCT = C.RSK_INDCT AND A.BAS_YYMM = C.BAS_YYMM AND A.BRNO = C.BRNO AND A.BAS_YYMM = #{BAS_YYMM}
AND A.BRNO = #{DSGN_VALT_BRNO}
AND A.RSK_CATG = #{CA}
AND C.RSK_GD_C = #{RSK_GD_C}

SELECT (SELECT RSK_CATG_NM FROM KRBA_RSK_CATG_I WHERE RSK_CATG = A.RSK_CATG) RSK_CATG     --위험카테고리
     , (SELECT RSK_EVT_NM 
          FROM KRBA_RSK_EVT_I
         WHERE RSK_CATG=B.RSK_CATG 
           AND RSK_FAC=B.RSK_FAC 
           AND RSK_EVT=B.RSK_EVT) AS RSK_EVT_NM   --위험이벤트
     , B.RSK_INDCT_NM    --위험지표명
     , B.RSK_INDCT_CTNT  --리스크상세설명
     , B.FRMUL_CTNT      --산식
  FROM KRBA_KRI_D       A
       JOIN KRBA_KRI_M  B
         ON A.RSK_INDCT = B.RSK_INDCT
 WHERE 1=1
   AND A.BAS_YYMM  = #{BAS_YYMM, jdbcType=VARCHAR}

   AND B.RSK_INDCT = #{RSK_INDCT, jdbcType=VARCHAR} 


   AND A.BRNO      = #{DSGN_VALT_BRNO, jdbcType=VARCHAR}


   AND A.RSK_CATG  = #{CA, jdbcType=VARCHAR}


   AND B.RSK_FAC   = #{FA, jdbcType=VARCHAR}


   AND B.RSK_EVT   = #{EV, jdbcType=VARCHAR}

SELECT 
	SUBSTR(BAS_YYMM,5)	 AS BAS_MM   	 --기준월
   ,INDE_RT								 --증감율
   ,PRS_QT_TRN_AMT                       --당분기거래금액
  FROM KRBA_KRI_D
 WHERE RSK_INDCT = #{RSK_INDCT, jdbcType=VARCHAR}
   AND BRNO = #{BRNO, jdbcType=VARCHAR}
   AND BAS_YYMM = #{BAS_YY, jdbcType=VARCHAR}||#{BAS_MM, jdbcType=VARCHAR}

SELECT RSK_INDCT    AS CD 		--위험지표
	  ,RSK_INDCT_NM AS CD_NM 	--위험지표명
  FROM KRBA_KRI_M
 WHERE 1=1

   AND RSK_CATG = #{RSK_CATG, jdbcType=VARCHAR}


   AND RSK_FAC  = #{RSK_FAC, jdbcType=VARCHAR}


   AND RSK_EVT  = #{RSK_EVT, jdbcType=VARCHAR}

