UPDATE KRBA_KRI_BRNO_D
SET AF_ACTN_CTNT = #{AF_ACTN_CTNT}
WHERE RSK_INDCT = #{RSK_INDCT}
  AND BRNO = #{BRNO}
  AND BAS_YYMM = #{BAS_YYMM}

mapper.select:
SELECT X.RSK_CATG_NM AS RSK_CATG_NM /* Risk Category */ , X.RSK_EVT_NM AS RSK_EVT_NM /* Risk Event */ , X.RSK_INDCT AS RSK_INDCT /* 지표번호 */ , X.RSK_INDCT_NM AS RSK_INDCT_NM /* Risk Indicator */ , Y.DTL_C_NM AS RSK_GD_C_NM /* 위험등급 */ , X.RSK_GD_C , X.BRNO_CNT AS BRNO_CNT /* 지점 수 */ , X.AVR_INDE_RT AS AVR_INDE_RT /* 평균 증감율 */ FROM (SELECT RSK_CATG_NM , RSK_EVT_NM , RSK_INDCT , RSK_INDCT_NM , RSK_GD_C , COUNT(*) AS BRNO_CNT , ROUND(AVG(INDE_RT), 2) || '%' AS AVR_INDE_RT FROM (SELECT D.RSK_CATG_NM , (SELECT RSK_EVT_NM FROM KRBA_RSK_EVT_I WHERE RSK_CATG = B.RSK_CATG AND RSK_FAC = B.RSK_FAC AND RSK_EVT = B.RSK_EVT) AS RSK_EVT_NM , B.RSK_INDCT , B.RSK_INDCT_NM , A.BRNO , A.INDE_RT --증감율 , A.RSK_CATG , B.RSK_EVT , C.RSK_GD_C FROM KRBA_KRI_D A /* RBA KRI 추출관리 */ JOIN KRBA_KRI_M B /* RBA KRI관리 */ ON A.RSK_INDCT = B.RSK_INDCT JOIN KRBA_KRI_BRNO_D C /* RBA KRI 부점별관리 */ ON A.RSK_INDCT = C.RSK_INDCT AND A.BAS_YYMM = C.BAS_YYMM AND A.BRNO = C.BRNO JOIN KRBA_RSK_CATG_I D /* RBA RISK CATEGORY */ ON A.RSK_CATG = D.RSK_CATG WHERE 1=1 AND A.BAS_YYMM = #{BAS_YYMM} ) WHERE 1=1
AND RSK_CATG = #{CA}
AND RSK_GD_C = #{RSK_GD_C}
GROUP BY RSK_CATG_NM, RSK_EVT_NM, RSK_INDCT, RSK_INDCT_NM, RSK_GD_C ) X JOIN KRBA_DTL_C Y ON Y.GRP_C = 'R335' AND X.RSK_GD_C = Y.DTL_C ORDER BY X.RSK_INDCT, Y.SNO

SELECT * FROM (SELECT A.BAS_YYMM ,D.RSK_CATG_NM ,(SELECT RSK_EVT_NM FROM KRBA_RSK_EVT_I WHERE RSK_CATG=B.RSK_CATG AND RSK_FAC=B.RSK_FAC AND RSK_EVT=B.RSK_EVT) AS RSK_EVT_NM ,B.RSK_INDCT_CTNT --위험지표설명 ,B.HTRH_CTNT --임계치내용 ,SUBSTR(A.BAS_YYMM,1,4)||SUBSTR(A.BAS_YYMM,5)+1||15 AS HNDL_DY_TM --조치일자 ,GET_USER_NAME(DECODE(B.CHG_OP_JKW_NO, NULL, DECODE(B.DR_OP_JKW_NO, NULL, 0, B.DR_OP_JKW_NO), B.CHG_OP_JKW_NO)) AS HNDL_P_ENO --담당자번호 ,A.BRNO ,GET_DEP_NAME(A.BRNO) BRNO_NM --부점명 ,CASE WHEN TO_NUMBER(TO_CHAR(SYSDATE,'YYYYMMDD')) <= TO_NUMBER(SUBSTR(A.BAS_YYMM,1,4)||SUBSTR(A.BAS_YYMM,5)+1||15) -- SYSDATE와 조치일자 비교 THEN CASE WHEN NVL(LENGTH(C.AF_ACTN_CTNT),0) > 0 THEN '조치완료' ELSE '조치 중' END ELSE CASE WHEN NVL(LENGTH(C.AF_ACTN_CTNT),0) > 0 THEN '조치완료' ELSE '기간초과' END END AS CNFR_ACTN_CTNT --조치상태 ,A.RSK_CATG ,B.RSK_INDCT ,B.RSK_INDCT_NM ,C.INDE_RT FROM KRBA_KRI_D A ,KRBA_KRI_M B ,KRBA_KRI_BRNO_D C ,KRBA_RSK_CATG_I D WHERE A.RSK_INDCT = B.RSK_INDCT AND A.BRNO = C.BRNO AND A.RSK_INDCT = C.RSK_INDCT AND A.BAS_YYMM = C.BAS_YYMM AND A.RSK_CATG = D.RSK_CATG AND C.RSK_GD_C = 'R' -- 위험등급 Red만 조회 AND A.BAS_YYMM >= #{BAS_YYMM_START} AND A.BAS_YYMM <= #{BAS_YYMM_END}
AND A.BRNO = #{DSGN_VALT_BRNO}
AND A.RSK_CATG = #{CA}
AND B.RSK_FAC = #{FA}
AND A.RSK_EVT = #{EV}
) AA WHERE 1 = 1
AND AA.CNFR_ACTN_CTNT in ('조치 중', '기간초과')
AND AA.CNFR_ACTN_CTNT = '조치완료'
ORDER BY AA.BAS_YYMM, AA.RSK_CATG

