UPDATE KRBA_TJACT_IMPRV_I
 SET   IMPRV_PROC_CTNT 	 = #{IMPRV_PROC_CTNT,jdbcType=VARCHAR}
     , IMPRV_PROC_JWK_NO = #{IMPRV_PROC_JWK_NO,jdbcType=VARCHAR}
     , IMPRV_DT			 = #{IMPRV_DT,jdbcType=VARCHAR}
     , FIX_YN			 = '0'

     , ATTCH_FILE_NO = #{ATTCH_FILE_NO , jdbcType=VARCHAR} 	--PARAM	평가회차 

     , CHG_DT= TO_CHAR(SYSDATE,'YYYYMMDD')
     , CHG_TIME= TO_CHAR(SYSDATE,'HH24MISS')
     , CHG_OP_JKW_NO= #{IMPRV_PROC_JWK_NO,jdbcType=VARCHAR}
 WHERE BAS_YYYY=#{BAS_YYYY,jdbcType=VARCHAR} 
 	   AND TONGJE_ACT_ID=#{TONGJE_ACT_ID,jdbcType=VARCHAR}

mapper.select:
SELECT A.BAS_YYYY AS BAS_YYYY /* 기준년도 */ , A.RSK_CATG AS RSK_CATG /* 위험CATEGORY */ , A.RSK_CATG ||'.'|| D.RSK_CATG_NM AS RSK_CATG_NM /* 위험CATEGORY 명 */ , A.RSK_FAC AS RSK_FAC /* 위험FACTOR */ , E.RSK_FAC_NM AS RSK_FAC_NM /* 위험FACTOR명 */ , A.RSK_EVT AS RSK_EVT /* 위험EVENT */ , B.RSK_EVT_NM AS RSK_EVT_NM /* 위험EVENT명 */ , A.RSK_EVT_CTNT AS RSK_EVT_CTNT /* 위험EVENT설명 */ , A.EXTR_POSS_YN AS EXTR_POSS_YN /* 산출가능성여부 */ , A.J_VALT_GD_C AS J_VALT_GD_C /* 정성평가등급코드 */ , A.EXPS_CNT AS EXPS_CNT /* 사례노출횟수 */ , A.EXPS_GD_C AS EXPS_GD_C /* 사례노출등급코드 */ , A.RSK_LVL_C AS RSK_LVL_C /* 위험LEVEL코드 */ , A.MSUR_TGT_YN AS MSUR_TGT_YN /* 측정대상여부 */ , CASE WHEN C.EVT_FIX_YN = '0' THEN 'N' WHEN C.EVT_FIX_YN = '1' THEN 'Y' END AS EVT_FIX_YN /* EVENT확정여부 */ , C.INDICT_FIX_YN AS INDICT_FIX_YN /* INDICATOR확정여부 */ FROM KRBA_RSK_EVT_M A /* RBA RISK EVENT 관리 */ LEFT OUTER JOIN KRBA_RSK_EVT_I B /* RBA RISK EVENT */ ON A.RSK_CATG = B.RSK_CATG AND A.RSK_FAC = B.RSK_FAC AND A.RSK_EVT = B.RSK_EVT LEFT OUTER JOIN (SELECT A.EVT_FIX_YN, A.INDICT_FIX_YN, B.BAS_YYYY FROM KRBA_VALT_SCHD_M A , KRBA_VALT_SCHD_D B WHERE A.BAS_YYYY = B.BAS_YYYY AND B.RSK_MNG_ACT_C = '2' /* 2. 위험식별 및 평가 */ AND B.RSK_MNG_ACT_DTL_C = '2.1' /* 2.1. ML/TF RISK EVENT 확정 */ ) C ON A.BAS_YYYY = C.BAS_YYYY LEFT OUTER JOIN KRBA_RSK_CATG_I D /* RBA RISK CATEGORY */ ON A.RSK_CATG = D.RSK_CATG LEFT OUTER JOIN KRBA_RSK_FAC_I E /* RBA RISK FACTOR */ ON A.RSK_CATG = E.RSK_CATG AND A.RSK_FAC = E.RSK_FAC WHERE A.BAS_YYYY = #{BAS_YYYY, jdbcType=VARCHAR}
AND A.RSK_CATG = #{RSK_CATG, jdbcType=VARCHAR}
AND A.RSK_FAC = #{RSK_FAC, jdbcType=VARCHAR}
