SELECT A.BAS_YYYY AS BAS_YYYY /* 기준년도 */ , A.RSK_CATG AS RSK_CATG /* 위험CATEGORY */ , D.RSK_CATG_NM AS RSK_CATG_NM /* 위험CATEGORY 명 */ , A.RSK_FAC AS RSK_FAC /* 위험FACTOR */ , E.RSK_FAC_NM AS RSK_FAC_NM /* 위험FACTOR명 */ , A.RSK_EVT AS RSK_EVT /* 위험EVENT */ , B.RSK_EVT_NM AS RSK_EVT_NM /* 위험EVENT명 */ , A.RSK_EVT_CTNT AS RSK_EVT_CTNT /* 위험EVENT설명 */ , C.EVT_FIX_YN AS EVT_FIX_YN /* EVENT확정여부 */ FROM KRBA_RSK_EVT_M A /* RBA RISK EVENT 관리 */ LEFT OUTER JOIN KRBA_RSK_EVT_I B /* RBA RISK EVENT */ ON A.RSK_CATG = B.RSK_CATG AND A.RSK_FAC = B.RSK_FAC AND A.RSK_EVT = B.RSK_EVT LEFT OUTER JOIN (SELECT A.EVT_FIX_YN, A.INDICT_FIX_YN, B.BAS_YYYY FROM KRBA_VALT_SCHD_M A , KRBA_VALT_SCHD_D B WHERE A.BAS_YYYY = B.BAS_YYYY AND B.RSK_MNG_ACT_C = '2' /* 2. 위험식별 및 평가 */ AND B.RSK_MNG_ACT_DTL_C = '2.1' /* 2.1. ML/TF RISK EVENT 확정 */ ) C ON A.BAS_YYYY = C.BAS_YYYY LEFT OUTER JOIN KRBA_RSK_CATG_I D /* RBA RISK CATEGORY */ ON A.RSK_CATG = D.RSK_CATG LEFT OUTER JOIN KRBA_RSK_FAC_I E /* RBA RISK FACTOR */ ON A.RSK_CATG = E.RSK_CATG AND A.RSK_FAC = E.RSK_FAC WHERE A.BAS_YYYY = #{BAS_YYYY, jdbcType=VARCHAR}
AND A.RSK_CATG = #{RSK_CATG, jdbcType=VARCHAR}
