SELECT A.BAS_YYYY AS BAS_YYYY /* 기준년도 */ , A.CH_ID AS CH_ID /* 취약점ID */ , A.TONGJE_FLD_C AS TONGJE_FLD_C /* 통제영역코드 */ , B.DTL_C_NM AS TONGJE_FLD_NM /* 통제영역코드 */ , A.TONGJE_PROC_C AS TONGJE_PROC_C /* 통제프로세스코드 */ , C.DTL_C_NM AS TONGJE_PROC_NM /* 통제프로세스코드 */ , A.TONGJE_SUB_PROC_C AS TONGJE_SUB_PROC_C /* 통제서브프로세스코드 */ , D.DTL_C_NM AS TONGJE_SUB_PROC_NM /* 통제서브프로세스코드 */ , A.CH_CTNT AS CH_CTNT /* 취약점내용 */ , A.CH_CAUS_C AS CH_CAUS_C /* 취약점원인코드 */ , E.DTL_C_NM AS CH_CAUS_NM /* 취약점원인코드 */ , A.CH_TP_LV1_C AS CH_TP_LV1_C /* 취약점유형LV1코드 */ , A.CH_TP_LV2_C AS CH_TP_LV2_C /* 취약점유형LV2코드 */ , A.EFCT_GD AS EFCT_GD /* 영향도등급 */ , A.OCC_POSS_GD AS OCC_POSS_GD /* 발생가능성등급 */ , A.CH_GD AS CH_GD /* 취약성등급 */ , A.GYLJ_S_C AS GYLJ_S_C /* 결재상태코드 */ , A.GYLJ_DT AS GYLJ_DT /* 결재일자 */ , A.GYLJ_JKW_NO AS GYLJ_JKW_NO /* 결재직원번호 */ , A.GYLJ_ID AS GYLJ_ID /* 결재ID */ , A.USYN AS USYN /* 사용여부 */ , CASE WHEN H.CH_FIX_YN = '1' THEN 'Y' ELSE 'N' END AS CH_FIX_YN /* 취약점확정여부 */ FROM KRBA_INTJ_CH_M A /* RBA 내부통제 취약점 */ LEFT OUTER JOIN (SELECT DTL_C, DTL_C_NM FROM KRBA_DTL_C WHERE GRP_C = 'R308') B ON A.TONGJE_FLD_C = B.DTL_C LEFT OUTER JOIN (SELECT DTL_C, DTL_C_NM FROM KRBA_DTL_C WHERE GRP_C = 'R309') C ON A.TONGJE_PROC_C = C.DTL_C LEFT OUTER JOIN (SELECT DTL_C, DTL_C_NM FROM KRBA_DTL_C WHERE GRP_C = 'R310') D ON A.TONGJE_SUB_PROC_C = D.DTL_C LEFT OUTER JOIN (SELECT DTL_C, DTL_C_NM FROM KRBA_DTL_C WHERE GRP_C = 'R320') E ON A.CH_CAUS_C = E.DTL_C LEFT OUTER JOIN KRBA_VALT_SCHD_M H /* RBA 위험평가 일정 */ ON A.BAS_YYYY = H.BAS_YYYY WHERE A.BAS_YYYY = #{BAS_YYYY, jdbcType=VARCHAR}
AND A.TONGJE_FLD_C = #{TONGJE_FLD_C, jdbcType=VARCHAR}
AND A.TONGJE_PROC_C = #{TONGJE_PROC_C, jdbcType=VARCHAR}
AND A.TONGJE_SUB_PROC_C = #{TONGJE_SUB_PROC_C, jdbcType=VARCHAR}
ORDER BY A.CH_ID

