 OUTER JOIN KRBA_VALT_SCHD_M H /* RBA 위험평가 일정 */ ON A.BAS_YYYY = H.BAS_YYYY LEFT OUTER JOIN C_USER I ON A.CHG_OP_JKW_NO = I.LOGIN_ID WHERE A.BAS_YYYY = #{BAS_YYYY, jdbcType=VARCHAR}
