AND A.TONGJE_SUB_PROC_C = #{TONGJE_SUB_PROC_C, jdbcType=VARCHAR}
ORDER BY A.CH_ID

SELECT A.BAS_YYYY AS BAS_YYYY /* 기준년도 */ , A.RSK_CATG AS RSK_CATG /* 위험CATEGORY */ , C.RSK_CATG_NM AS RSK_CATG_NM /* 위험CATEGORY */ , A.RSK_FAC AS RSK_FAC /* 위험FACTOR */ , A.RSK_LVL_C AS RSK_LVL_C /* 위험LEVEL코드 */ , CASE WHEN A.RSK_CATG = '5' THEN '일반요인' ELSE D.DTL_C_NM || '위험' END AS RSK_LVL_NM /* 위험LEVEL코드 */ , A.RSK_EVT AS RSK_EVT /* 위험EVENT */ , E.RSK_EVT_NM AS RSK_EVT_NM /* 위험EVENT */ , A.RSK_EVT_CTNT AS RSK_EVT_CTNT /* 위험EVENT설명 */ , A.EXTR_POSS_YN AS EXTR_POSS_YN /* 산출가능성여부 */ , A.J_VALT_GD_C AS J_VALT_GD_C /* 정성평가등급코드 */ , A.EXPS_CNT AS EXPS_CNT /* 사례노출횟수 */ , A.EXPS_GD_C AS EXPS_GD_C /* 사례노출등급코드 */ , A.MSUR_TGT_YN AS MSUR_TGT_YN /* 측정대상여부 */ , B.RSK_INDCT AS RSK_INDCT /* 위험INDICATOR */ , B.RSK_INDCT_NO AS RSK_INDCT_NO /* 위험INDICATOR번호 */ , B.RSK_INDCT_NM AS RSK_INDCT_NM /* 위험INDICATOR명 */ , B.RSK_INDCT_CTNT AS RSK_INDCT_CTNT /* 위험INDICATOR설명 */ , B.EXTR_TGT_YN AS EXTR_TGT_YN /* 산출대상여부 */ , CASE WHEN B.EXTR_TGT_YN = 1 THEN 'Y' ELSE 'N' END AS EXTR_TGT_YN_NM /* 산출대상여부 */ , B.EST_METH AS EST_METH /* 산정방법 */ , B.VB_DEFI_CTNT AS VB_DEFI_CTNT /* 변수정의내용 */ , B.EXTR_BAS AS EXTR_BAS /* 추출기준 */ , B.RUN_FRQ AS RUN_FRQ /* 작업주기 */ , B.APR_UNIT_C AS APR_UNIT_C /* 평가단위코드 */ , F.INDICT_FIX_YN AS INDICT_FIX_YN /* INDICATOR확정여부 */ FROM KRBA_RSK_EVT_M A LEFT OUTER JOIN KRBA_RSK_INDCT_M B ON A.BAS_YYYY = B.BAS_YYYY AND A.RSK_CATG = B.RSK_CATG AND A.RSK_FAC = B.RSK_FAC AND A.RSK_EVT = B.RSK_EVT LEFT OUTER JOIN KRBA_RSK_CATG_I C ON A.RSK_CATG = C.RSK_CATG LEFT OUTER JOIN (SELECT DTL_C, DTL_C_NM FROM KRBA_DTL_C WHERE GRP_C = 'R332') D ON A.RSK_LVL_C = D.DTL_C LEFT OUTER JOIN KRBA_RSK_EVT_I E ON A.RSK_CATG = E.RSK_CATG AND A.RSK_FAC = E.RSK_FAC AND A.RSK_EVT = E.RSK_EVT LEFT OUTER JOIN KRBA_VALT_SCHD_M F ON A.BAS_YYYY = F.BAS_YYYY WHERE A.BAS_YYYY = #{BAS_YYYY,JDBCTYPE=VARCHAR}
AND A.RSK_CATG = #{RSK_CATG,JDBCTYPE=VARCHAR}
AND A.RSK_FAC = #{RSK_FAC,JDBCTYPE=VARCHAR}
AND A.RSK_EVT = #{RSK_EVT,JDBCTYPE=VARCHAR}
AND A.RSK_LVL_C = #{RSK_LVL_C,JDBCTYPE=VARCHAR}
ORDER BY A.RSK_CATG, A.RSK_EVT, A.RSK_LVL_C DESC, B.RSK_INDCT_NO

mapper.update:
UPDATE KRBA_RSK_INDCT_M
  SET EXTR_TGT_YN = #{EXTR_TGT_YN, JDBCTYPE=NUMERIC}
    , CHG_DT = TO_CHAR(SYSDATE,'YYYYMMDD')
    , CHG_TIME = TO_CHAR(SYSDATE,'HH24MISS')
    , CHG_OP_JKW_NO = #{CHG_OP_JKW_NO, JDBCTYPE=VARCHAR}
 WHERE BAS_YYYY = #{BAS_YYYY, JDBCTYPE=VARCHAR}
   AND RSK_INDCT = #{RSK_INDCT, JDBCTYPE=VARCHAR}

UPDATE KRBA_RSK_INDCT_M
   SET RSK_INDCT_NM = #{RSK_INDCT_NM, JDBCTYPE=VARCHAR}
     , RSK_INDCT_CTNT = #{RSK_INDCT_CTNT, JDBCTYPE=VARCHAR}
     , EXTR_TGT_YN = #{EXTR_TGT_YN, JDBCTYPE=NUMERIC}
     , EST_METH = #{EST_METH, JDBCTYPE=VARCHAR}
     , VB_DEFI_CTNT = #{VB_DEFI_CTNT, JDBCTYPE=VARCHAR}
     , EXTR_BAS = #{EXTR_BAS, JDBCTYPE=VARCHAR}
     , RUN_FRQ = #{RUN_FRQ, JDBCTYPE=VARCHAR}
     , APR_UNIT_C = #{APR_UNIT_C, JDBCTYPE=VARCHAR}
     , CHG_DT = TO_CHAR(SYSDATE,'YYYYMMDD')
     , CHG_TIME = TO_CHAR(SYSDATE,'HH24MISS')
     , CHG_OP_JKW_NO = #{CHG_OP_JKW_NO, JDBCTYPE=VARCHAR}
 WHERE BAS_YYYY = #{BAS_YYYY, JDBCTYPE=VARCHAR}
   AND RSK_INDCT = #{RSK_INDCT, JDBCTYPE=VARCHAR}

