SELECT CASE WHEN A.RSK_CATG = '999' THEN '합계' ELSE B.RSK_CATG_NM END AS RSK_CATG_NM , A.* , #{BRNO,JDBCTYPE=VARCHAR} AS BRNO FROM (SELECT NVL(A.RSK_CATG, '999') AS RSK_CATG , TO_CHAR(SUM(CASE WHEN A.SRVC_G_C = '01' THEN A.JIPYO_V ELSE 0 END)) AS SRVC_01 , TO_CHAR(SUM(CASE WHEN A.SRVC_G_C = '02' THEN A.JIPYO_V ELSE 0 END)) AS SRVC_02 , TO_CHAR(SUM(CASE WHEN A.SRVC_G_C = '03' THEN A.JIPYO_V ELSE 0 END)) AS SRVC_03 , TO_CHAR(SUM(CASE WHEN A.SRVC_G_C = '04' THEN A.JIPYO_V ELSE 0 END)) AS SRVC_04 , TO_CHAR(SUM(CASE WHEN A.SRVC_G_C = '05' THEN A.JIPYO_V ELSE 0 END)) AS SRVC_05 , TO_CHAR(SUM(CASE WHEN A.SRVC_G_C = '06' THEN A.JIPYO_V ELSE 0 END)) AS SRVC_06 , TO_CHAR(SUM(CASE WHEN A.SRVC_G_C = '07' THEN A.JIPYO_V ELSE 0 END)) AS SRVC_07 , TO_CHAR(SUM(CASE WHEN A.SRVC_G_C = '08' THEN A.JIPYO_V ELSE 0 END)) AS SRVC_08 , TO_CHAR(SUM(CASE WHEN A.SRVC_G_C = '09' THEN A.JIPYO_V ELSE 0 END)) AS SRVC_09 , TO_CHAR(SUM(CASE WHEN A.SRVC_G_C = '10' THEN A.JIPYO_V ELSE 0 END)) AS SRVC_10 , TO_CHAR(SUM(CASE WHEN A.SRVC_G_C = '11' THEN A.JIPYO_V ELSE 0 END)) AS SRVC_11 , TO_CHAR(SUM(CASE WHEN A.SRVC_G_C = '12' THEN A.JIPYO_V ELSE 0 END)) AS SRVC_12 , TO_CHAR(SUM(A.JIPYO_V)) AS SRVC_TOTAL FROM KRBA_EXPS_EXTR_M A /* RBA 노출위험 지표추출관리 */ WHERE A.BAS_YYYY = #{BAS_YYYY, JDBCTYPE=VARCHAR} AND A.VALT_TRN = #{VALT_TRN, JDBCTYPE=VARCHAR}
AND A.BRNO = #{BRNO,JDBCTYPE=VARCHAR}
GROUP BY ROLLUP(A.RSK_CATG) ORDER BY A.RSK_CATG ) A LEFT OUTER JOIN KRBA_RSK_CATG_I B ON A.RSK_CATG = B.RSK_CATG

SELECT ROUND(AVG(A.EXPS_SCOR),2) AS EXPS_SCOR /* 노출위험SCORE */ , ROUND(AVG(B.BSRSK_SCOR),2) AS BSRSK_SCOR /* 사업위험SCORE */ , ROUND(AVG(A.BZRSK_GD),0) AS BSRSK_GD /* 사업위험등급 */ , SUM(C.EXPS_AMT) AS EXPS_AMT /* MLTF 위험거래금액(노출금액) */ , ROUND(AVG(A.MLTF_RSK_SCOR),2) AS MLTF_RSK_SCOR /* MLTF SCORE */ FROM KRBA_MLTF_EXTR_I A /* RBA ML/TF 위험산출 SCORE */ LEFT OUTER JOIN KRBA_BZRSK_LST_I B /* RBA 사업위험 최종결과 */ ON A.BAS_YYYY = B.BAS_YYYY AND A.VALT_TRN = B.VALT_TRN AND A.BRNO = B.BRNO LEFT OUTER JOIN KRBA_EXPS_SCOR_I C ON A.BAS_YYYY = C.BAS_YYYY AND A.VALT_TRN = C.VALT_TRN AND A.BRNO = C.BRNO WHERE A.BAS_YYYY = #{BAS_YYYY, JDBCTYPE=VARCHAR} AND A.VALT_TRN = #{VALT_TRN, JDBCTYPE=NUMERIC}
AND A.BRNO = #{BRNO, JDBCTYPE=VARCHAR}
GROUP BY A.BAS_YYYY, A.VALT_TRN

SELECT A.BAS_YYYY /* 기준년도 */ , A.TONGJE_ACT_ID /* 통제활동ID */ , A.CH_ID /* 취약점ID */ , A.TONGJE_ACT_TITE /* 통제활동제목 */ , A.TONGJE_ACT_DTL /* 통제활동상세 */ , A.TONGJE_FLD_C /* 통제영역코드 */ , A.TONGJE_PROC_C /* 통제프로세스코드 */ , A.TONGJE_SUB_PROC_C /* 통제서브프로세스코드 */ , A.SRVC_01 /* 사망보험 - 보험 */ , A.SRVC_02 /* 생존보험 - 보험 */ , A.SRVC_03 /* 생사보험 - 보험 */ , A.SRVC_04 /* 변액보험 - 보험 */ , A.SRVC_05 /* 단체보험 - 보험 */ , A.SRVC_06 /* 기업형 - 퇴직연금 */ , A.SRVC_07 /* 개인형 - 퇴직연금 */ , A.SRVC_08 /* 약관대출 - 대출 */ , A.SRVC_09 /* 신용대출 - 대출 */ , A.SRVC_10 /* 담보대출 - 대출 */ , A.SRVC_11 /* PF대출 - 대출 */ , A.SRVC_12 /* 수익증권 */ , B.DTL_C_NM AS TONGJE_FLD_NM /* 통제영역코드 */ , C.DTL_C_NM AS TONGJE_PROC_NM /* 통제프로세스코드 */ , D.DTL_C_NM AS TONGJE_SUB_PROC_NM /* 통제서브프로세스코드 */ FROM (SELECT A.BAS_YYYY /* 기준년도 */ , A.TONGJE_ACT_ID /* 통제활동ID */ , A.CH_ID /* 취약점ID */ , A.TONGJE_ACT_TITE /* 통제활동제목 */ , A.TONGJE_ACT_DTL /* 통제활동상세 */ , B.TONGJE_FLD_C /* 통제영역코드 */ , B.TONGJE_PROC_C /* 통제프로세스코드 */ , B.TONGJE_SUB_PROC_C /* 통제서브프로세스코드 */ , MAX(CASE WHEN C.SRVC_G_C = '01' THEN C.USYN END) AS SRVC_01 , MAX(CASE WHEN C.SRVC_G_C = '02' THEN C.USYN END) AS SRVC_02 , MAX(CASE WHEN C.SRVC_G_C = '03' THEN C.USYN END) AS SRVC_03 , MAX(CASE WHEN C.SRVC_G_C = '04' THEN C.USYN END) AS SRVC_04 , MAX(CASE WHEN C.SRVC_G_C = '05' THEN C.USYN END) AS SRVC_05 , MAX(CASE WHEN C.SRVC_G_C = '06' THEN C.USYN END) AS SRVC_06 , MAX(CASE WHEN C.SRVC_G_C = '07' THEN C.USYN END) AS SRVC_07 , MAX(CASE WHEN C.SRVC_G_C = '08' THEN C.USYN END) AS SRVC_08 , MAX(CASE WHEN C.SRVC_G_C = '09' THEN C.USYN END) AS SRVC_09 , MAX(CASE WHEN C.SRVC_G_C = '10' THEN C.USYN END) AS SRVC_10 , MAX(CASE WHEN C.SRVC_G_C = '11' THEN C.USYN END) AS SRVC_11 , MAX(CASE WHEN C.SRVC_G_C = '12' THEN C.USYN END) AS SRVC_12 FROM KRBA_TJ_ACT_M A /* RBA 통제활동 */ JOIN KRBA_INTJ_CH_M B /* RBA 내부통제 취약점 */ ON A.BAS_YYYY = B.BAS_YYYY AND A.CH_ID = B.CH_ID JOIN KRBA_TJ_ACT_SVC_MP C /* RBA 통제활동 서비스별 매핑 */ ON A.BAS_YYYY = C.BAS_YYYY AND A.TONGJE_ACT_ID = C.TONGJE_ACT_ID WHERE A.BAS_YYYY = #{BAS_YYYY, JDBCTYPE=VARCHAR}
AND B.TONGJE_FLD_C = #{TONGJE_FLD_C,JDBCTYPE=VARCHAR}
AND B.TONGJE_PROC_C = #{TONGJE_PROC_C,JDBCTYPE=VARCHAR}
AND B.TONGJE_SUB_PROC_C = #{TONGJE_SUB_PROC_C,JDBCTYPE=VARCHAR}
GROUP BY A.BAS_YYYY /* 기준년도 */ , A.TONGJE_ACT_ID /* 통제활동ID */ , A.CH_ID /* 취약점ID */ , A.TONGJE_ACT_TITE /* 통제활동제목 */ , A.TONGJE_ACT_DTL /* 통제활동상세 */ , B.TONGJE_FLD_C /* 통제영역코드 */ , B.TONGJE_PROC_C /* 통제프로세스코드 */ , B.TONGJE_SUB_PROC_C /* 통제서브프로세스코드 */ ORDER BY A.TONGJE_ACT_ID ) A LEFT OUTER JOIN (SELECT DTL_C, DTL_C_NM FROM KRBA_DTL_C WHERE GRP_C = 'R308') B ON A.TONGJE_FLD_C = B.DTL_C LEFT OUTER JOIN (SELECT DTL_C, DTL_C_NM FROM KRBA_DTL_C WHERE GRP_C = 'R309') C ON A.TONGJE_PROC_C = C.DTL_C LEFT OUTER JOIN (SELECT DTL_C, DTL_C_NM FROM KRBA_DTL_C WHERE GRP_C = 'R310') D ON A.TONGJE_SUB_PROC_C = D.DTL_C

