UPDATE KRBA_TJ_ACT_SVC_MP
   SET USYN = #{USYN, JDBCTYPE=NUMERIC}
     , DR_DT = TO_CHAR(SYSDATE,'YYYYMMDD')
     , DR_TIME = TO_CHAR(SYSDATE,'HH24MISS')
     , DR_OP_JKW_NO = #{DR_OP_JKW_NO, JDBCTYPE=VARCHAR}
 WHERE BAS_YYYY = #{BAS_YYYY, JDBCTYPE=VARCHAR}
   AND TONGJE_ACT_ID = #{TONGJE_ACT_ID, JDBCTYPE=VARCHAR}
   AND SRVC_G_C = #{SRVC_G_C, JDBCTYPE=VARCHAR}

