SELECT A.RSK_CATG , B.RSK_CATG_NM , A.RSK_EVT , C.RSK_EVT_NM , TO_CHAR(SUM(CASE WHEN A.SRVC_G_C = '01' THEN A.JIPYO_V ELSE 0 END)) AS SRVC_01 , TO_CHAR(SUM(CASE WHEN A.SRVC_G_C = '02' THEN A.JIPYO_V ELSE 0 END)) AS SRVC_02 , TO_CHAR(SUM(CASE WHEN A.SRVC_G_C = '03' THEN A.JIPYO_V ELSE 0 END)) AS SRVC_03 , TO_CHAR(SUM(CASE WHEN A.SRVC_G_C = '04' THEN A.JIPYO_V ELSE 0 END)) AS SRVC_04 , TO_CHAR(SUM(CASE WHEN A.SRVC_G_C = '05' THEN A.JIPYO_V ELSE 0 END)) AS SRVC_05 , TO_CHAR(SUM(CASE WHEN A.SRVC_G_C = '06' THEN A.JIPYO_V ELSE 0 END)) AS SRVC_06 , TO_CHAR(SUM(CASE WHEN A.SRVC_G_C = '07' THEN A.JIPYO_V ELSE 0 END)) AS SRVC_07 , TO_CHAR(SUM(CASE WHEN A.SRVC_G_C = '08' THEN A.JIPYO_V ELSE 0 END)) AS SRVC_08 , TO_CHAR(SUM(CASE WHEN A.SRVC_G_C = '09' THEN A.JIPYO_V ELSE 0 END)) AS SRVC_09 , TO_CHAR(SUM(CASE WHEN A.SRVC_G_C = '10' THEN A.JIPYO_V ELSE 0 END)) AS SRVC_10 , TO_CHAR(SUM(CASE WHEN A.SRVC_G_C = '11' THEN A.JIPYO_V ELSE 0 END)) AS SRVC_11 , TO_CHAR(SUM(CASE WHEN A.SRVC_G_C = '12' THEN A.JIPYO_V ELSE 0 END)) AS SRVC_12 , TO_CHAR(SUM(A.JIPYO_V)) AS SRVC_TOTAL FROM KRBA_EXPS_EXTR_M A /* RBA 노출위험 지표추출관리 */ LEFT OUTER JOIN KRBA_RSK_CATG_I B /* RBA RISK CATEGORY */ ON A.RSK_CATG = B.RSK_CATG LEFT OUTER JOIN KRBA_RSK_EVT_I C /* RBA RISK EVENT */ ON A.RSK_CATG = C.RSK_CATG AND SUBSTR(A.RSK_INDCT, 2, 2) = C.RSK_FAC AND A.RSK_EVT = C.RSK_EVT WHERE A.BAS_YYYY = #{BAS_YYYY, JDBCTYPE=VARCHAR} AND A.VALT_TRN = #{VALT_TRN, JDBCTYPE=VARCHAR}
AND A.RSK_INDCT LIKE #{RSK_CATG,JDBCTYPE=VARCHAR}||#{RSK_FAC,JDBCTYPE=VARCHAR}||#{RSK_EVT,JDBCTYPE=VARCHAR}||'%'
AND A.INDV_CORP_CCD = #{INDV_CORP_CCD,JDBCTYPE=VARCHAR}
AND A.BRNO = #{BRNO,JDBCTYPE=VARCHAR}
AND A.RSK_CATG = #{RSK_CATG,JDBCTYPE=VARCHAR}
AND A.RSK_EVT = #{RSK_EVT,JDBCTYPE=VARCHAR}
AND A.RSK_LVL_C = #{RSK_LVL_C,JDBCTYPE=VARCHAR}
GROUP BY A.RSK_CATG , B.RSK_CATG_NM , A.RSK_EVT , C.RSK_EVT_NM ORDER BY A.RSK_CATG, A.RSK_EVT

/* RBA_30_03_06_01_doSearch 사업위험 산출조회 */ SELECT I.RSK_CATG AS RSK_CATG , CAT.RSK_CATG_NM AS RSK_CATG_NM , I.RSK_EVT AS RSK_EVT , EVT.RSK_EVT_NM AS RSK_EVT_NM , I.RSK_INDCT_NO AS RSK_INDCT_NO , I.RSK_INDCT_CTNT AS RSK_INDCT_CTNT , TO_CHAR(SUM(JIPYO_V),'999,999,999,999,999')||' '||C.DTL_C_NM AS JIPYO_V , TRUNC(ROUND(COALESCE(AVG((S.SCOR)),0),2),2) AS SCOR FROM KRBA_BZRSK_EXTR_M B INNER JOIN KRBA_RSK_INDCT_M I ON I.RSK_CATG||I.RSK_FAC||I.RSK_EVT||I.RSK_INDCT_NO = B.RSK_INDCT AND I.BAS_YYYY = B.BAS_YYYY INNER JOIN KRBA_BZRSK_EXTR_T1 S ON S.RSK_INDCT = B.RSK_INDCT AND S.BAS_YYYY = B.BAS_YYYY AND S.VALT_TRN = B.VALT_TRN AND S.BRNO = B.BRNO INNER JOIN KRBA_RSK_CATG_I CAT ON CAT.RSK_CATG = B.RSK_CATG INNER JOIN KRBA_RSK_EVT_I EVT ON EVT.RSK_CATG = B.RSK_CATG AND EVT.RSK_EVT = B.RSK_EVT LEFT OUTER JOIN KRBA_DTL_C C ON C.GRP_C = 'R337' AND C.DTL_C = I.APR_UNIT_C WHERE B.BAS_YYYY = #{BAS_YYYY, JDBCTYPE=VARCHAR} AND B.VALT_TRN = #{VALT_TRN, JDBCTYPE=NUMERIC}
AND B.BRNO = #{BRNO,JDBCTYPE=VARCHAR}
AND I.RSK_CATG = #{RSK_CATG,JDBCTYPE=VARCHAR}
AND I.RSK_FAC = #{RSK_FAC,JDBCTYPE=VARCHAR}
AND I.RSK_EVT = #{RSK_EVT,JDBCTYPE=VARCHAR}
GROUP BY I.RSK_CATG , CAT.RSK_CATG_NM , I.RSK_EVT , EVT.RSK_EVT_NM , I.RSK_INDCT_NO , I.RSK_INDCT_CTNT , C.DTL_C_NM ORDER BY I.RSK_CATG, I.RSK_EVT, I.RSK_INDCT_NO

mapper.update:
	UPDATE /* RBA_30.RBA_30_04_03_1N_doSaveTP_ATTCH_FILE_NO */
	       KRBA_BRNO_VALT_M A  /* RBA 부점별 통제운영평가 */
	   SET A.TP_ATTCH_FILE_NO   = #{TP_ATTCH_FILE_NO, jdbcType=NUMERIC}
	     , A.CHG_DT             = #{CHG_DT, jdbcType=VARCHAR}
	     , A.CHG_TIME           = #{CHG_TIME, jdbcType=VARCHAR}
	     , A.CHG_OP_JKW_NO      = #{CHG_OP_JKW_NO, jdbcType=VARCHAR}
	 WHERE 1=1
	   AND A.BAS_YYYY           = #{BAS_YYYY, jdbcType=VARCHAR}
	   AND A.TONGJE_OPR_VALT_ID = #{TONGJE_OPR_VALT_ID, jdbcType=VARCHAR}
       AND A.VALT_TRN           = #{VALT_TRN, jdbcType=VARCHAR}
       AND A.VALT_BRNO          = #{VALT_BRNO, jdbcType=VARCHAR}
